const ACTIVITIES = [
// ===== BEACHES & WATER =====
{id:1,name:"Hanauma Bay Nature Preserve",category:"beaches",address:"7455 Kalanianaole Hwy",driveTime:"8 min",distance:"4 mi",description:"Famous snorkeling bay in a volcanic crater. Shallow, calm inner reef perfect for kids with hundreds of tropical fish. Educational marine life center included with admission.",cost:"$25/person, kids 12 & under free",hours:"Wed-Sun (closed Mon & Tue)",kidInfo:"Shallow calm inner reef perfect for kids. Educational center with marine life exhibits.",tips:"Reservations required online. Go early for best snorkeling visibility. Bring your own snorkel gear to save money.",region:"East Oahu",wiki:"Hanauma_Bay",tags:["snorkeling","marine life","crater","reservations required"]},
{id:2,name:"Sandy Beach Park",category:"beaches",address:"8801 Kalanianaole Hwy",driveTime:"10 min",distance:"5 mi",description:"Beautiful golden sand beach famous for bodyboarding. Strong shorebreak makes it dangerous for swimming but great for sand play and watching skilled bodyboarders.",cost:"Free",hours:"Open daily",kidInfo:"NOT safe for swimming (strong shorebreak). Great for sand play and watching bodyboarders.",tips:"Do not swim here - even locals get injured. Perfect for photos and sand castles.",region:"East Oahu",wiki:"Sandy_Beach",tags:["bodyboarding","scenic","sand play","dangerous surf"]},
{id:3,name:"Kuhio Beach Ponds",category:"beaches",address:"Kuhio Beach, Waikiki",driveTime:"20 min",distance:"9 mi",description:"Concrete wall enclosure creates a protected wading pool right in Waikiki. Virtually no waves inside the pond - perfect for toddlers and nervous swimmers. Lifeguards on duty.",cost:"Free",hours:"Open daily, lifeguards 9am-5:30pm",kidInfo:"Perfect shallow wading pool for toddlers. No waves inside the enclosure. Lifeguards on duty.",tips:"Less crowded on weekday mornings. Free hula show most evenings at sunset nearby.",region:"Waikiki",wiki:"Kuhio_Beach",tags:["toddler-friendly","wading","lifeguards","waikiki"]},
{id:4,name:"Duke Kahanamoku Lagoon",category:"beaches",address:"Hilton Hawaiian Village, Waikiki",driveTime:"20 min",distance:"10 mi",description:"Man-made lagoon at the Hilton with virtually no waves. Gradual slope and calm water ideal for nervous swimmers and toddlers. Free public access.",cost:"Free",hours:"Open daily",kidInfo:"Ideal for nervous swimmers and toddlers. Virtually no waves, gradual slope.",tips:"Free to access even though it's at the Hilton. Friday night fireworks at 7:45pm right here.",region:"Waikiki",wiki:"Duke_Kahanamoku_Lagoon",tags:["toddler-friendly","calm water","fireworks friday"]},
{id:5,name:"Ala Moana Beach Park",category:"beaches",address:"1201 Ala Moana Blvd",driveTime:"20 min",distance:"9 mi",description:"Calm, shallow, reef-protected beach with a great playground. Much less crowded than Waikiki with better parking. Large grassy areas for picnics and play.",cost:"Free",hours:"Open daily",kidInfo:"Calm shallow water, great playground on site. Much less crowded than Waikiki.",tips:"Great alternative to Waikiki. Combine with Ala Moana Center mall trip. Good restrooms and showers.",region:"Honolulu",wiki:"Ala_Moana_Beach_Park",tags:["playground","calm water","less crowded","family"]},
{id:6,name:"Waialae Beach Park (Kahala Beach)",category:"beaches",address:"4925 Kahala Ave",driveTime:"10 min",distance:"4 mi",description:"Quiet, uncrowded beach next to the Kahala Hotel. Calm shallow water with gradual slope ideal for toddlers. Playground, BBQ grills, and picnic tables.",cost:"Free",hours:"Open daily",kidInfo:"Calm shallow water, gradual slope ideal for toddlers. Playground and BBQ grills.",tips:"Much less crowded than Waikiki. Local families use this beach. Great for BBQ days.",region:"Kahala",wiki:"Waialae_Beach_Park",tags:["quiet","playground","bbq","toddler-friendly"]},
{id:7,name:"Maunalua Bay Beach Park",category:"beaches",address:"6505 Kalanianaole Hwy",driveTime:"5 min",distance:"2 mi",description:"Calm bay for wading and splashing very close to your rental. Large grassy area, picnic tables, restrooms. Hawaii Kai Towne Center across the street for food.",cost:"Free",hours:"Open daily",kidInfo:"Calm bay water for wading. Large grassy area for play.",tips:"Super close to home. Great for a quick afternoon splash. Food options across the street.",region:"Hawaii Kai",wiki:"Maunalua_Bay",tags:["close to home","calm water","quick trip"]},
{id:8,name:"Kailua Beach Park",category:"beaches",address:"526 Kawailoa Rd, Kailua",driveTime:"25 min",distance:"12 mi",description:"Consistently rated one of America's best beaches. Calm turquoise water over white sand with gentle waves perfect for families. Kayak rentals available to paddle to Mokulua Islands.",cost:"Free",hours:"Open daily",kidInfo:"Calm turquoise water, gentle waves, white sand. One of the best family beaches in Hawaii.",tips:"Free parking but fills early on weekends. Kayak rentals available. Combine with Kailua town lunch.",region:"Windward",wiki:"Kailua_Beach",tags:["top-rated","turquoise water","kayaking","white sand"]},
{id:9,name:"Lanikai Beach",category:"beaches",address:"Mokulua Dr, Kailua",driveTime:"25 min",distance:"13 mi",description:"Postcard-perfect beach with powdery white sand and crystal clear turquoise water. Protective reef creates flat, calm conditions ideal for families. Kayak to Mokulua Islands visible offshore.",cost:"Free",hours:"Open daily",kidInfo:"Flat calm water due to protective reef. Ideal for families with small children.",tips:"Limited street parking only - arrive early. No facilities (use Kailua Beach Park nearby). Worth the parking hassle.",region:"Windward",wiki:"Lanikai_Beach",tags:["postcard-perfect","calm water","limited parking"]},
{id:10,name:"Waimanalo Beach",category:"beaches",address:"41 Kalanianaole Hwy, Waimanalo",driveTime:"20 min",distance:"10 mi",description:"Over 3 miles of white sand beach with turquoise water. Much less crowded than Waikiki with a local vibe. Gentle waves good for kids.",cost:"Free",hours:"Open daily",kidInfo:"Gentle waves, long stretch of sand for running. Less crowded, local vibe.",tips:"One of the longest beaches on Oahu. Local families love this beach. Combine with Ono Steaks nearby.",region:"Windward",wiki:"Waimanalo_Beach",tags:["uncrowded","long beach","local vibe","gentle waves"]},
{id:11,name:"Ko Olina Lagoons",category:"beaches",address:"Ko Olina Resort, Kapolei",driveTime:"45 min",distance:"28 mi",description:"Four man-made lagoons with the calmest water on Oahu. Sandy bottom, virtually no waves - perfect for toddlers. Free public access with limited parking.",cost:"Free",hours:"Open daily",kidInfo:"PERFECT for toddlers. Calmest water on the island. Sandy bottom, no waves at all.",tips:"Arrive early for free public parking (limited spots). Restrooms and showers available. Can combine with Aulani Disney breakfast.",region:"West Oahu",wiki:"Ko_Olina",tags:["calmest water","toddler paradise","man-made lagoons","arrive early"]},
{id:12,name:"Bellows Field Beach Park",category:"beaches",address:"220 Tinker Rd, Waimanalo",driveTime:"20 min",distance:"10 mi",description:"Military beach open to public on weekends and holidays only (Fri noon - Sun midnight). Locals know this is one of the best beaches on the island. Gentle waves, ironwood shade trees, uncrowded.",cost:"Free",hours:"Fri noon - Sun midnight only",kidInfo:"Gentle waves, shaded areas under ironwood trees. One of the best kept secrets.",tips:"Only open weekends/holidays. Get there Friday afternoon for the best experience. Camping available.",region:"Windward",wiki:"Bellows_Air_Force_Station",tags:["weekend only","uncrowded","local secret","shade trees"]},
{id:13,name:"Kuliouou Beach Park",category:"beaches",address:"165 Kuliouou Rd",driveTime:"5 min",distance:"1.5 mi",description:"Neighborhood beach where local families BBQ on weekends. Calm, shallow reef-protected water. BBQ grills, picnic tables, shade trees. Almost zero tourists.",cost:"Free",hours:"Open daily",kidInfo:"Calm shallow reef-protected water. BBQ grills and shade for families.",tips:"This is where locals hang out on weekends. Bring charcoal for the BBQ grills. Great way to meet neighborhood families.",region:"East Oahu",wiki:null,tags:["local","bbq","close to home","uncrowded"]},
{id:14,name:"Shark's Cove",category:"beaches",address:"59-712 Kamehameha Hwy, North Shore",driveTime:"55 min",distance:"35 mi",description:"Excellent tide pools and snorkeling in a natural lava rock formation. Summer only (dangerous in winter). Like a natural aquarium - kids can explore marine life in shallow pools.",cost:"Free",hours:"Open daily (summer only for water)",kidInfo:"Natural tide pools for exploring. Water shoes essential - rocky entry. Summer only.",tips:"Only safe in summer (May-Sept). Water shoes are a must. Bring snorkel gear. Amazing underwater life in the pools.",region:"North Shore",wiki:"Sharks_Cove",tags:["tide pools","snorkeling","summer only","lava rock"]},
{id:15,name:"Halona Beach Cove (Eternity Beach)",category:"beaches",address:"Below Halona Blowhole, Kalanianaole Hwy",driveTime:"10 min",distance:"5 mi",description:"Hidden pocket beach accessible by a short scramble down from the Blowhole parking lot. Calm in summer with turquoise water. Famous filming location for From Here to Eternity.",cost:"Free",hours:"Open daily",kidInfo:"Carry kids down the rocky path. Check conditions before entering water.",tips:"Park at Halona Blowhole lot. Short but steep scramble down. Beautiful for photos. Sea turtles sometimes visible.",region:"East Oahu",wiki:"Halona_Beach_Cove",tags:["hidden beach","scenic","movie location","scramble required"]},

// ===== HIKES & TRAILS =====
{id:20,name:"Makapuu Lighthouse Trail",category:"hikes",address:"Near Sea Life Park, Kalanianaole Hwy",driveTime:"15 min",distance:"7 mi",description:"Paved 2-mile round-trip trail with stunning ocean views. One of the best whale-watching spots on Oahu (March!). Steady uphill but fully paved - manageable for rugged strollers.",cost:"Free",hours:"Sunrise to sunset",kidInfo:"Paved trail, stroller-possible with rugged stroller. 5-year-old can walk the whole thing. Carry 3-year-old or use carrier.",tips:"Go early morning for cooler temps. No shade on trail - bring sunscreen and water. Whale watching in March is amazing from here.",region:"East Oahu",wiki:"Makapu%CA%BBu_Point",tags:["paved","whale watching","ocean views","stroller-possible"]},
{id:21,name:"Diamond Head Summit Trail",category:"hikes",address:"Diamond Head Rd, Waikiki",driveTime:"15 min",distance:"6 mi",description:"Iconic 1.6-mile round-trip crater hike with 360-degree views of Waikiki, Honolulu, and the ocean. Includes stairs (99 + 76 steps + spiral staircase) and a tunnel. Exciting for kids.",cost:"$5/person, reservations required",hours:"6am-4pm (last entry)",kidInfo:"5-year-old can do this with encouragement. Carry 3-year-old for stair sections. Tunnel and bunker at top are exciting.",tips:"Go at 7:30am to avoid heat and crowds. Reservations required. Bring water. The spiral staircase and WWII bunker are the highlights for kids.",region:"Waikiki",wiki:"Diamond_Head_(Hawaii)",tags:["iconic","crater","stairs","panoramic views","reservations"]},
{id:22,name:"Koko Crater Botanical Garden Loop",category:"hikes",address:"Inside Koko Crater, off Kealaolu Ave",driveTime:"10 min",distance:"4 mi",description:"2-mile loop trail through a 60-acre garden inside a volcanic crater. Cacti, succulents, plumeria groves - feels like another planet. FREE and virtually no crowds.",cost:"Free",hours:"Sunrise to sunset",kidInfo:"Easy trail, mostly flat. Jogging stroller works. Kids love the unusual plants - feels like Arizona inside a Hawaii crater.",tips:"Bring water - no shade inside the crater. Very few people. One of the most unique short walks on Oahu.",region:"East Oahu",wiki:"Koko_Crater_Botanical_Garden",tags:["free","botanical","volcanic crater","uncrowded","easy"]},
{id:23,name:"Kawainui Marsh Path",category:"hikes",address:"704 Kaha St, Kailua",driveTime:"25 min",distance:"12 mi",description:"Paved, flat 1.5-mile path through Hawaii's largest wetland. Completely wheelchair and stroller accessible. Waterbirds, mountain views, lush marshland. Almost exclusively used by locals.",cost:"Free",hours:"7am-7pm",kidInfo:"Completely flat paved path. Perfect for strollers. Bring binoculars for bird watching.",tips:"Morning is best for birds (Hawaiian coots, stilts, ducks). Almost no tourists - this is a local walking path.",region:"Windward",wiki:"Kawainui_Marsh",tags:["flat","paved","stroller-friendly","bird watching","free"]},
{id:24,name:"Hoomaluhia Botanical Garden",category:"hikes",address:"45-680 Luluku Rd, Kaneohe",driveTime:"30 min",distance:"15 mi",description:"400-acre tropical garden with dramatic Ko'olau mountain backdrop. Multiple paved walking paths, a lake with catch-and-release fishing, and stunning photo opportunities. One of Oahu's most photogenic spots.",cost:"Free admission and parking",hours:"9am-4pm, closed Mondays",kidInfo:"Stroller-friendly on main roads. Free catch-and-release fishing gear on weekends. Peacocks roam the grounds.",tips:"Drive in and park at different sections. One of the most Instagrammable spots on Oahu. Combine with Byodo-In Temple nearby.",region:"Windward",wiki:"Ho%CA%BBomaluhia_Botanical_Garden",tags:["free","400 acres","mountains","fishing","photogenic"]},
{id:25,name:"Waimea Valley Walk to Waterfall",category:"hikes",address:"59-864 Kamehameha Hwy, Haleiwa",driveTime:"50 min",distance:"32 mi",description:"Fully paved, stroller-friendly 1.5-mile round-trip walk through a botanical garden to a 45-foot swimmable waterfall. Free life jackets provided. Ducks and peacocks along the path.",cost:"Adults $25, Kids 4-12 $14, under 3 free",hours:"9am-4pm daily",kidInfo:"Fully paved and stroller-friendly. One of the few swimmable waterfalls on Oahu. Free life jackets at the falls.",tips:"Bring swimsuits and towels. The walk through the garden is beautiful even if too cold to swim. Ducks and peacocks delight kids.",region:"North Shore",wiki:"Waimea_Valley",tags:["waterfall","swimmable","stroller-friendly","botanical garden","paved"]},
{id:26,name:"Lanikai Pillbox Hike (Kaiwa Ridge)",category:"hikes",address:"265 Kaelepulu Dr, Kailua",driveTime:"25 min",distance:"13 mi",description:"1.7-mile round-trip ridge hike with jaw-dropping views of Lanikai Beach, Mokulua Islands, and turquoise ocean. WWII pillboxes (concrete bunkers) at the top - kids love climbing on them.",cost:"Free",hours:"Sunrise to sunset",kidInfo:"First 10 min is steep but short. After that, gentle ridge walking. Carry 3-year-old up steep part. Pillbox bunkers are fun to explore.",tips:"Sunrise here is legendary. Residential street parking - be respectful. The steep part is brief, then it's easy ridge walking.",region:"Windward",wiki:null,tags:["ridge hike","pillbox","ocean views","sunrise spot"]},
{id:27,name:"Likeke Falls",category:"hikes",address:"Old Pali Rd, near Pali Hwy",driveTime:"25 min",distance:"12 mi",description:"One of Oahu's shortest waterfall hikes at just 0.9 miles round trip through a magical bamboo forest. Small waterfall with mountain stream. Very lush and enchanting.",cost:"Free",hours:"Sunrise to sunset",kidInfo:"Short enough for both kids to walk with help. Muddy - bring shoes you don't care about. Magical bamboo forest setting.",tips:"Muddy year-round - old shoes are a must. Very lush and magical feeling. One of the easiest waterfall hikes for young kids.",region:"Windward",wiki:null,tags:["waterfall","short hike","bamboo","muddy","magical"]},
{id:28,name:"Manoa Falls Trail",category:"hikes",address:"3860 Manoa Rd",driveTime:"25 min",distance:"11 mi",description:"1.6-mile round-trip rainforest hike to a spectacular 150-foot waterfall. Giant banyan trees, bamboo groves, and lush vegetation. One of the most popular hikes on Oahu.",cost:"$5 parking (cash)",hours:"Sunrise to sunset",kidInfo:"5-year-old can walk the whole thing. Carry 3-year-old for the second half if tired. No swimming at the falls.",tips:"Very muddy - old shoes are a must. Bug spray essential. Morning is best. Combine with Lyon Arboretum next door.",region:"Honolulu",wiki:"Manoa_Falls",tags:["waterfall","rainforest","muddy","150 feet","popular"]},
{id:29,name:"Ka'iwi Shoreline Trail",category:"hikes",address:"Near Makapuu, Kalanianaole Hwy",driveTime:"15 min",distance:"7 mi",description:"Dramatic rocky coastline trail from Makapuu area. Tide pools, hidden coves, and possible whale spouts offshore. Do as much or as little as you want - 1.5 miles one way.",cost:"Free",hours:"Sunrise to sunset",kidInfo:"Rugged stroller possible for first half. Lots of tide pools for kids to explore. Watch for rogue waves near the edge.",tips:"Explore at your own pace. Many spots to stop and poke around tide pools. Stunning coastal scenery close to home.",region:"East Oahu",wiki:null,tags:["coastal","tide pools","flexible distance","close to home"]},
{id:30,name:"Foster Botanical Garden",category:"hikes",address:"180 N Vineyard Blvd, Chinatown",driveTime:"25 min",distance:"11 mi",description:"Oahu's oldest botanical garden (1853). Giant ancient trees, orchids, a poisonous plant garden behind glass, and prehistoric-looking plants. The cannonball tree is incredible.",cost:"Adults $5, kids 6-12 $1, under 6 free",hours:"9am-4pm, closed holidays",kidInfo:"Small enough to not overwhelm little kids. Shaded throughout. Interesting unusual plants.",tips:"Good for a hot day - lots of shade. Small and manageable for young attention spans. Near Chinatown for lunch.",region:"Honolulu",wiki:"Foster_Botanical_Garden",tags:["botanical","shaded","historic","small"]},
{id:31,name:"Judd Trail (Jackass Ginger Pool)",category:"hikes",address:"Nu'uanu Pali Dr",driveTime:"20 min",distance:"9 mi",description:"1.3-mile rainforest loop with a stream, banyan trees, and a shallow swimming hole called Jackass Ginger Pool. Short and gentle enough for little legs.",cost:"Free",hours:"Sunrise to sunset",kidInfo:"Swimming hole is shallow and gentle - great for kids on a hot day. Short enough for little legs.",tips:"Trail is muddy year-round. The swimming hole is the highlight. Bring towels and a change of clothes.",region:"Honolulu",wiki:null,tags:["swimming hole","rainforest","loop trail","muddy"]},
{id:32,name:"Kapiolani Park Loop",category:"hikes",address:"Kapiolani Park, Waikiki",driveTime:"18 min",distance:"8 mi",description:"Easy 1.5-mile loop around Oahu's largest public park (300 acres). Paved paths past banyan trees, Diamond Head views, and peacocks near the zoo fence. Great for strollers and bikes.",cost:"Free",hours:"Open daily",kidInfo:"Completely flat and paved. Stroller-friendly. Large open fields for kids to run. Peacocks near zoo fence.",tips:"Combine with zoo or aquarium visit. Great picnic spot under the banyan trees. Playground on site.",region:"Waikiki",wiki:"Kapiolani_Park",tags:["flat","paved","stroller-friendly","playground","banyan trees"]},

// ===== RESTAURANTS =====
{id:40,name:"Mud Hen Water",category:"dining",address:"3452 Waialae Ave, Kaimuki",driveTime:"15 min",distance:"6 mi",description:"Modern Hawaiian restaurant where about half the menu can be made gluten-free. Staff very familiar with celiac needs - some staff have celiac themselves. GF brownie dessert available.",cost:"$$",hours:"Tue-Sat dinner",kidInfo:"Accommodating for families. Staff extremely knowledgeable about dietary restrictions.",gfInfo:"~Half the menu can be GF. Staff have celiac experience. GF brownie dessert. Servers consult chefs on every order.",tips:"Menu not marked GF but servers are very knowledgeable. Call ahead: (808) 737-6000. One of the best GF-friendly restaurants on Oahu.",region:"Kaimuki",wiki:null,tags:["modern hawaiian","gluten-free","celiac-friendly","kaimuki"]},
{id:41,name:"Olive Tree Cafe",category:"dining",address:"4614 Kilauea Ave",driveTime:"12 min",distance:"4 mi",description:"Beloved Greek/Mediterranean counter-service spot with many naturally gluten-free options. Grilled meats, hummus, babaganoush, rice dishes. Outdoor seating. CASH ONLY. Est. 1995.",cost:"$",hours:"Open daily for dinner",kidInfo:"Casual counter-service format is easy with kids. Outdoor seating.",gfInfo:"Many naturally GF options: grilled meats, hummus, babaganoush, rice. Not a dedicated GF kitchen.",tips:"CASH ONLY! No reservations. Can be a wait but moves fast. One of the best value meals in Honolulu.",region:"Kahala",wiki:null,tags:["greek","cash only","affordable","outdoor seating","gluten-free"]},
{id:42,name:"Kona Brewing Co.",category:"dining",address:"7192 Kalanianaole Hwy, Koko Marina",driveTime:"8 min",distance:"3 mi",description:"Your closest brewpub with outdoor lanai and ocean views. Good craft beers, pizza, and pub food. GF cauliflower crust pizza available. Kid-friendly patio.",cost:"$$",hours:"Open daily 11am-9pm",kidInfo:"Kid-friendly patio with ocean views. Good casual family dinner spot.",gfInfo:"Cauliflower crust pizza available (+$6 sub on 10\" pie). GF menu items marked. Cross-contamination possible.",tips:"Close to home - great for a casual dinner. Outdoor seating is the best spot. Busy on weekends.",region:"Hawaii Kai",wiki:"Kona_Brewing_Company",tags:["brewpub","pizza","ocean views","close to home","gluten-free"]},
{id:43,name:"Koko Head Cafe",category:"dining",address:"1120 12th Ave, Kaimuki",driveTime:"15 min",distance:"6 mi",description:"Extremely popular brunch spot in Kaimuki with creative Hawaiian-fusion breakfast dishes. Expect long lines on weekends. Now open for dinner Fri-Mon.",cost:"$$",hours:"Daily 7am-2pm, Fri-Mon dinner 5-9pm",kidInfo:"Popular brunch - can be long waits. Good for adventurous young eaters.",gfInfo:"Some dishes can be modified GF. Ask server for options.",tips:"Arrive early or expect a wait, especially weekends. Worth it for the creative brunch menu. Dinner is less crowded.",region:"Kaimuki",wiki:null,tags:["brunch","popular","long lines","kaimuki","creative"]},
{id:44,name:"Cafe Maharani",category:"dining",address:"2509 S King St",driveTime:"20 min",distance:"9 mi",description:"Authentic Indian restaurant with huge portions. Many curries and rice dishes are naturally gluten-free. Tandoori meats are GF. No reservations - arrive when it opens.",cost:"$$",hours:"Open daily",kidInfo:"Huge portions great for sharing with kids. Rice and tandoori dishes are mild options for kids.",gfInfo:"Many curries and rice dishes naturally GF. Tandoori meats are GF. Ask about naan alternatives.",tips:"No reservations - arrive when it opens to avoid wait. Huge portions. Phone: (808) 951-7447.",region:"Honolulu",wiki:null,tags:["indian","gluten-free","huge portions","no reservations"]},
{id:45,name:"The Pig and the Lady",category:"dining",address:"83 N King St, Chinatown",driveTime:"25 min",distance:"11 mi",description:"Vietnamese fusion restaurant in Chinatown with creative dishes. Many rice noodle and rice-based dishes are naturally GF. Famous for their inventive pho variations.",cost:"$$",hours:"Mon-Sat lunch & dinner",kidInfo:"Rice noodle dishes are approachable for kids. Pho is always a kid winner.",gfInfo:"Many rice noodle and rice-based dishes naturally GF. Confirm soy sauce is tamari.",tips:"One of Honolulu's most acclaimed restaurants. Lunch is more casual. Chinatown location great for exploring.",region:"Chinatown",wiki:null,tags:["vietnamese fusion","acclaimed","chinatown","gluten-free","pho"]},
{id:46,name:"Rainbow Drive-In",category:"dining",address:"3308 Kanaina Ave",driveTime:"18 min",distance:"8 mi",description:"Iconic local plate lunch spot since 1961. Rice plates with various meat choices. Fast, affordable, and a true Honolulu institution. Great for a quick family meal.",cost:"$",hours:"Open daily 7am-9pm",kidInfo:"Quick and affordable. Rice plates are easy for kids. Casual outdoor seating.",gfInfo:"Rice plates with meat choices are GF-adaptable. Avoid gravy (contains flour).",tips:"Iconic local spot - been here since 1961. Quick and cheap. Perfect for a no-fuss family meal.",region:"Kapahulu",wiki:null,tags:["plate lunch","iconic","affordable","quick","since 1961"]},
{id:47,name:"Teddy's Bigger Burgers",category:"dining",address:"7192 Kalanianaole Hwy, Koko Marina",driveTime:"8 min",distance:"3 mi",description:"Quality burger joint right in Koko Marina near home. Udi's gluten-free buns available. Staff knowledgeable about celiac needs.",cost:"$",hours:"Open daily",kidInfo:"Burgers are always a kid winner. Close to home for easy dinners.",gfInfo:"Udi's GF buns available. Staff knowledgeable about celiac needs. Not a dedicated GF facility.",tips:"Close to home in Koko Marina. Solid burgers with GF bun option.",region:"Hawaii Kai",wiki:null,tags:["burgers","close to home","gluten-free buns","quick"]},
{id:48,name:"Moena Cafe",category:"dining",address:"7192 Kalanianaole Hwy, Koko Marina",driveTime:"8 min",distance:"3 mi",description:"Popular brunch and breakfast spot in Koko Marina known for accommodating dietary restrictions. Rice-based dishes available. Great close-to-home breakfast option.",cost:"$$",hours:"Open daily for breakfast/lunch",kidInfo:"Known for dietary accommodation. Rice-based dishes for kids. Close to home.",gfInfo:"Known for accommodating dietary restrictions. Rice-based dishes available.",tips:"Your closest quality brunch spot. Can get busy on weekends. Right in Koko Marina.",region:"Hawaii Kai",wiki:null,tags:["brunch","close to home","dietary friendly","koko marina"]},
{id:49,name:"Plumeria Beach House",category:"dining",address:"5000 Kahala Ave, Kahala Hotel",driveTime:"12 min",distance:"4 mi",description:"Beautiful oceanfront restaurant at the Kahala Hotel with an extensive allergen menu. Staff well-trained on dietary needs. Special occasion worthy.",cost:"$$$",hours:"Breakfast, lunch & dinner daily",kidInfo:"Staff trained on dietary needs. Beautiful oceanfront setting impresses kids.",gfInfo:"Extensive allergen menu. Staff trained on dietary needs. Chef accommodates GF requests.",tips:"Great for a special dinner out. Oceanfront setting is beautiful at sunset. Reserve ahead.",region:"Kahala",wiki:null,tags:["oceanfront","special occasion","kahala hotel","allergen menu"]},
{id:50,name:"Helena's Hawaiian Food",category:"dining",address:"1240 N School St",driveTime:"25 min",distance:"13 mi",description:"James Beard Award-winning traditional Hawaiian food. Pipikaula, laulau, squid luau - the real deal. Local institution since 1946. No frills, just incredible authentic food.",cost:"$",hours:"Tue-Fri only",kidInfo:"Casual atmosphere. Great for introducing kids to authentic Hawaiian food.",gfInfo:"Many traditional Hawaiian dishes are naturally GF (poi, kalua pork, laulau). Confirm preparation.",tips:"James Beard Award winner. Only open Tue-Fri. Arrive early - they sell out. A true local institution since 1946.",region:"Kalihi",wiki:null,tags:["hawaiian food","james beard","traditional","institution","since 1946"]},
{id:51,name:"Side Street Inn",category:"dining",address:"1225 Hopaka St",driveTime:"20 min",distance:"10 mi",description:"Famous among locals for legendary pork chops and fried rice served family-style. Big portions perfect for sharing. Where Honolulu chefs eat after their shifts.",cost:"$$",hours:"Open daily, dinner",kidInfo:"Family-style portions great for sharing. Fried rice is a kid favorite.",gfInfo:"Some dishes modifiable. Fried rice is GF. Famous pork chops are GF.",tips:"Where local chefs eat after work. Family-style portions are huge. The pork chops are legendary.",region:"Honolulu",wiki:null,tags:["family-style","pork chops","fried rice","local favorite","chefs choice"]},
{id:52,name:"Pioneer Saloon",category:"dining",address:"3046 Monsarrat Ave",driveTime:"18 min",distance:"7 mi",description:"Japanese-Hawaiian plate lunch hidden gem near Diamond Head. Katsu curry, mochiko chicken, loco moco. Order at counter, eat at picnic tables. $9-15 per plate.",cost:"$",hours:"Open daily",kidInfo:"Casual counter service. Rice plates easy for kids. Outdoor picnic table seating.",gfInfo:"Rice-based plates available. Avoid breaded items (katsu). Grilled options with rice are GF.",tips:"Hidden gem near Diamond Head. Local favorite. Combine with a Diamond Head hike. $9-15 per plate.",region:"Kapahulu",wiki:null,tags:["plate lunch","japanese-hawaiian","affordable","near diamond head"]},

// ===== FOOD TRUCKS & LOCAL EATS =====
{id:60,name:"Giovanni's Shrimp Truck",category:"foodtrucks",address:"56-505 Kamehameha Hwy, Kahuku",driveTime:"55 min",distance:"36 mi",description:"The original North Shore shrimp truck. Famous garlic shrimp scampi - 12 jumbo shrimp in buttery garlic sauce with 2 scoops rice. Truck covered in Sharpie signatures. Also a 'No Refunds' spicy option.",cost:"$15-18/plate",hours:"10:30am-6:30pm daily",kidInfo:"Garlic shrimp with rice is a crowd-pleaser for kids. Covered outdoor seating.",tips:"The original and most famous. Cash preferred. Also has locations in Haleiwa and H Mart Honolulu.",region:"North Shore",wiki:null,tags:["shrimp","iconic","north shore","garlic"]},
{id:61,name:"Big Wave Shrimp",category:"foodtrucks",address:"66-521 Kamehameha Hwy, Haleiwa",driveTime:"50 min",distance:"32 mi",description:"Featured on Diners, Drive-Ins and Dives. Multiple shrimp flavors plus chicken and ribs for picky eaters. They'll peel shrimp for $1 extra - great for little hands.",cost:"$14/plate",hours:"10am-6:30pm",kidInfo:"Will peel shrimp for $1 extra - great for little hands. Chicken/ribs option for picky eaters.",tips:"The $1 peeling service is a game-changer with young kids. Featured on DDD. Multiple flavor options.",region:"North Shore",wiki:null,tags:["shrimp","diners drive-ins dives","peeling service","kid-friendly"]},
{id:62,name:"Mike's Huli Chicken",category:"foodtrucks",address:"Kamehameha Hwy, Kahuku",driveTime:"55 min",distance:"36 mi",description:"Hawaiian-style huli huli chicken broiled over kiawe wood. Featured on Diners, Drive-Ins and Dives. BBQ chicken is always a kid win. Covered outdoor seating.",cost:"$12-16/plate",hours:"11:30am-6:30pm (closed Wed)",kidInfo:"BBQ chicken is universally loved by kids. Covered outdoor seating.",tips:"Closed Wednesdays. Featured on DDD. The smoky kiawe wood flavor is incredible. Near the macadamia farm.",region:"North Shore",wiki:null,tags:["huli chicken","bbq","diners drive-ins dives","kid-friendly"]},
{id:63,name:"Romy's Kahuku Prawns",category:"foodtrucks",address:"56-781 Kamehameha Hwy, Kahuku",driveTime:"55 min",distance:"36 mi",description:"Farm-raised prawns cooked fresh from their own ponds. Butter garlic, spicy, or classic preparations. Outdoor picnic tables near Kahuku Farms.",cost:"$14-18/plate",hours:"Open daily",kidInfo:"Fresh prawns are fun for kids to eat. Outdoor seating near the farm.",tips:"They raise their own prawns on site. Near Kahuku Farms - combine for a half-day trip.",region:"North Shore",wiki:null,tags:["prawns","farm-raised","fresh","north shore"]},
{id:64,name:"Uncle Clay's House of Pure Aloha",category:"foodtrucks",address:"820 W Hind Dr, Aina Haina",driveTime:"2 min",distance:"0.5 mi",description:"Right in your neighborhood! Famous shave ice and soft-serve made with fresh, natural syrups. The kids will want to come here daily. A true Aina Haina institution.",cost:"$5-8",hours:"Open daily",kidInfo:"Walking distance from home. Fresh natural syrups. Kids will beg to come daily.",tips:"Your neighborhood shave ice spot. Fresh natural syrups set it apart. Walking distance from the rental!",region:"Aina Haina",wiki:null,tags:["shave ice","walking distance","neighborhood","daily treat"]},
{id:65,name:"Ono Steaks and Shrimp Shack",category:"foodtrucks",address:"41-037 Wailea St, Waimanalo",driveTime:"20 min",distance:"10 mi",description:"Yellow-table food truck with the motto 'Suck, peel, dip, and EAT.' Garlic shrimp, fresh fish tacos, local plate lunches. Fun casual vibe.",cost:"$12-16/plate",hours:"Mon-Sat 10:30am-5pm (closed Tue)",kidInfo:"Garlic shrimp plates with rice are naturally GF. Casual outdoor setting.",gfInfo:"Garlic shrimp plates with rice are naturally GF. Fresh grilled fish options.",tips:"Closed Tuesdays. Great lunch stop after Waimanalo Beach. The garlic shrimp is fantastic.",region:"Windward",wiki:null,tags:["shrimp","plate lunch","waimanalo","casual"]},
{id:66,name:"Ted's Bakery",category:"foodtrucks",address:"59-024 Kamehameha Hwy, Haleiwa",driveTime:"55 min",distance:"35 mi",description:"Famous among locals for chocolate haupia cream pie - a must-try. Also serves plate lunches. While tourists hit Matsumoto's for shave ice, locals come here for pie.",cost:"$5-7/slice, $10-16/plate",hours:"Open daily",kidInfo:"Kids love the chocolate haupia cream pie. Plate lunches available too.",tips:"The chocolate haupia cream pie is legendary. Locals know this is the real North Shore food stop. Buy a whole pie to take home.",region:"North Shore",wiki:null,tags:["pie","haupia","local favorite","bakery","north shore"]},
{id:67,name:"Haleiwa Bowls",category:"foodtrucks",address:"66-030 Kamehameha Hwy, Haleiwa",driveTime:"50 min",distance:"32 mi",description:"Best acai bowls on the North Shore. The 'Local Bowl' features frozen acai, granola, poi, banana, papaya, honey, and coconut. Colorful, healthy, and kids love them.",cost:"Small $13, Large $16",hours:"7:30am-6pm",kidInfo:"Colorful acai bowls are fun and healthy. Kids love picking toppings.",tips:"Best acai bowls on the North Shore. Great fuel after a morning at the beach.",region:"North Shore",wiki:null,tags:["acai bowls","healthy","colorful","north shore"]},
{id:68,name:"Waiahole Poi Factory",category:"foodtrucks",address:"48-140 Kamehameha Hwy, Kaneohe",driveTime:"30 min",distance:"16 mi",description:"Tiny roadside spot serving fresh poi, laulau, kalua pig, and haupia. Where local families go for authentic Hawaiian food. No frills, just incredible traditional food.",cost:"$10-15/plate",hours:"Open daily",kidInfo:"Great for introducing kids to authentic Hawaiian food. Casual atmosphere.",tips:"Cash preferred. This is where locals eat, not tourists. Try the fresh poi and laulau.",region:"Windward",wiki:null,tags:["hawaiian food","poi","authentic","local","roadside"]},
{id:69,name:"North Shore Crepes Cafe",category:"foodtrucks",address:"Haleiwa",driveTime:"50 min",distance:"32 mi",description:"French owner making authentic crepes - both sweet (Nutella banana) and savory (ham & cheese). Perfect kid food that's a nice change from shrimp plates.",cost:"$8-14",hours:"9am-4pm",kidInfo:"Crepes are perfect kid food. Sweet Nutella banana crepes are a hit.",tips:"Nice change of pace from shrimp trucks. Authentic French crepes. Good breakfast stop in Haleiwa.",region:"North Shore",wiki:null,tags:["crepes","french","breakfast","haleiwa"]},
{id:70,name:"Kahai Street Kitchen",category:"foodtrucks",address:"680 Ala Moana Blvd",driveTime:"20 min",distance:"10 mi",description:"Hidden lunch counter with incredible loco moco, kalbi, and garlic shrimp. A favorite of local workers - not a tourist destination at all.",cost:"$10-15",hours:"Lunch hours",kidInfo:"Loco moco and rice plates are easy for kids. Casual counter service.",tips:"Hidden gem where locals eat lunch. Not fancy but the food is outstanding. Near the waterfront.",region:"Honolulu",wiki:null,tags:["hidden gem","loco moco","local workers","lunch"]},

// ===== ADVENTURES =====
{id:80,name:"Atlantis Submarine",category:"adventures",address:"Hilton Hawaiian Village, Waikiki",driveTime:"20 min",distance:"10 mi",description:"Real submarine dive to 100 feet underwater. See shipwrecks, turtles, sharks, and coral reefs through large viewports. 45-50 minutes underwater. A once-in-a-lifetime family experience.",cost:"Adults ~$113, Kids ~$57",hours:"Multiple departures daily",kidInfo:"Kids must be 3+ and 36\" tall. Both kids should qualify. Incredible experience for young minds.",tips:"Book online for best prices. The submarine is surprisingly spacious. Kids are mesmerized by the underwater views.",region:"Waikiki",wiki:"Atlantis_Submarines",tags:["submarine","underwater","unique","once-in-a-lifetime"]},
{id:81,name:"Holokai Catamaran",category:"adventures",address:"Departs from Waikiki Beach",driveTime:"20 min",distance:"10 mi",description:"Board directly from the sand - no harbor needed. Sail to Turtle Canyon to snorkel with green sea turtles. Also sunset sails and whale watching (March = humpback season!).",cost:"$50-80/person, use code TC15 for 15% off",hours:"Multiple daily sailings",kidInfo:"All ages welcome. Board right from the beach. Whale watching in March is incredible.",tips:"Use promo code TC15 for 15% off through March 2026. Book whale watching tour for March - humpback season. Board from Waikiki sand.",region:"Waikiki",wiki:null,tags:["catamaran","snorkeling","turtles","whale watching","promo code"]},
{id:82,name:"Surfing Lessons (Waikiki)",category:"adventures",address:"Waikiki Beach",driveTime:"20 min",distance:"9 mi",description:"Learn to surf in the gentle birthplace-of-surfing waves. For young kids, instructors do tandem surfing (ride with the child). Multiple schools available.",cost:"Group $75-150, Private $150-300",hours:"Daily, typically 7am-3pm",kidInfo:"Tandem surfing available for young kids (instructor rides with child). Ages 5+ for solo. 1.5-2 hours with gear included.",tips:"Sparky's Surf School is #1 on TripAdvisor (ages 5+). Ohana Surf Project offers family format (1 adult + 1 child). Waikiki waves are gentle and perfect for learning.",region:"Waikiki",wiki:null,tags:["surfing","lessons","tandem","waikiki"]},
{id:83,name:"Kayaking to Mokulua Islands",category:"adventures",address:"Kailua Beach",driveTime:"25 min",distance:"12 mi",description:"Paddle tandem kayaks across turquoise water to twin islands visible from Lanikai Beach. Land on Moku Nui, explore tide pools. About 1 hour each way. Kids ride in front seat.",cost:"Tandem full-day $75-90, half-day $55-65",hours:"Rentals open early morning",kidInfo:"Kids ride in the front seat of tandem kayaks. Explore tide pools on the island.",tips:"Kailua Beach Adventures has 40+ years experience. Half-day is plenty. Bring water and snacks for the island.",region:"Windward",wiki:"Mokulua",tags:["kayaking","islands","turquoise water","adventure"]},
{id:84,name:"Kualoa Ranch",category:"adventures",address:"49-560 Kamehameha Hwy, Kaneohe",driveTime:"35 min",distance:"18 mi",description:"4,000-acre working cattle ranch and Jurassic Park filming location. Multiple tour options: Hollywood Movie Sites bus tour (all ages), Jungle Expedition (ages 3+), UTV Raptor (5+), horseback, zipline.",cost:"From $60 half-day, packages from ~$125 with lunch",hours:"Open daily, tours start 8am",kidInfo:"Jungle Expedition ages 3+ (both kids qualify). Movie Sites bus tour is all ages. Ocean activities include kayaks and glass-bottom boats.",tips:"Book the Jungle Expedition or Movie Tour for young kids. Half-day package with lunch is best value. The valley scenery is absolutely stunning.",region:"Windward",wiki:"Kualoa_Ranch",tags:["jurassic park","ranch","movie locations","multiple tours","valley"]},
{id:85,name:"Coral Crater Adventure Park",category:"adventures",address:"91-1780 Midway Rd, Kapolei",driveTime:"45 min",distance:"28 mi",description:"35-acre adventure park with six ziplines (300-1,000 ft), aerial adventure tower, 50-foot climbing walls, freefall experience, and rappelling.",cost:"$90-170",hours:"Open daily",kidInfo:"Minimum age 6 for ziplines - the 5.5-year-old is borderline (check when you visit). Aerial tower has obstacles for various ages.",tips:"Call ahead to confirm age requirements for the 5.5-year-old. The ziplines are spectacular. Book online for better rates.",region:"West Oahu",wiki:null,tags:["zipline","climbing","adventure park","age minimum"]},
{id:86,name:"Horseback Riding - Turtle Bay",category:"adventures",address:"Turtle Bay Resort, North Shore",driveTime:"55 min",distance:"35 mi",description:"Pony rides for ages 6 and under along the North Shore coast - kids groom, feed, and ride a pony. Both kids qualify for pony rides. Trail rides for ages 7+.",cost:"$85-150",hours:"Multiple ride times daily",kidInfo:"Pony rides specifically for ages 6 & under - both kids qualify! Groom and feed the pony too.",tips:"Book pony rides in advance. Beautiful coastal setting. The kids get to groom and feed the horses too.",region:"North Shore",wiki:"Turtle_Bay_Resort",tags:["horseback","pony rides","coastal","north shore"]},
{id:87,name:"Gunstock Ranch",category:"adventures",address:"56-250 Kamehameha Hwy, Kahuku",driveTime:"55 min",distance:"36 mi",description:"Pony rides specifically designed for ages 2-7. Trail rides on the ranch with mountain and ocean views. Great for horse-loving kids.",cost:"Varies by ride",hours:"Open daily",kidInfo:"Pony rides ages 2-7 - perfect for both kids. Designed specifically for young children.",tips:"Specifically designed for young kids, unlike most horse ranches. Book in advance.",region:"North Shore",wiki:null,tags:["pony rides","young kids","ranch","ages 2-7"]},
{id:88,name:"Wet 'n' Wild Hawaii",category:"adventures",address:"400 Farrington Hwy, Kapolei",driveTime:"45 min",distance:"28 mi",description:"Full water park with slides, lazy river, wave pool, and dedicated kids' area. Great for a full day when you want something different from the beach.",cost:"Check website for current prices",hours:"Seasonal hours vary",kidInfo:"Dedicated kids' area with age-appropriate slides and water play. Lazy river is fun for all ages.",tips:"Check website for seasonal hours and pricing. Pack lunch to save money. Bring sunscreen - not much shade.",region:"West Oahu",wiki:"Wet_%27n%27_Wild_Hawaii",tags:["water park","slides","lazy river","full day"]},
{id:89,name:"Sea Life Park - Dolphin Encounters",category:"adventures",address:"41-202 Kalanianaole Hwy, Waimanalo",driveTime:"15 min",distance:"7 mi",description:"Multiple dolphin interaction levels: Dolphin Aloha (dry land, ages 1+), Dolphin Encounter (shallow water), Dolphin Exploration (deep, ages 8+). All include park admission.",cost:"$54-99+ per person",hours:"10am-4pm (closed Tuesdays)",kidInfo:"Dolphin Aloha is ages 1+ (meet dolphins from platform). Perfect for the 3-year-old. Park admission included.",tips:"Very close to home! Dolphin Aloha (dry land) is perfect for young kids. Book online. Closed Tuesdays.",region:"East Oahu",wiki:"Sea_Life_Park_Hawaii",tags:["dolphins","marine park","close to home","interactive"]},
{id:90,name:"Parasailing",category:"adventures",address:"Kewalo Basin Harbor, Waikiki",driveTime:"20 min",distance:"10 mi",description:"Soar 600-1,000 feet above the ocean with up to 3 people tandem. Non-flyers can ride the boat as observers for ~$50.",cost:"$75-120/person, observers ~$50",hours:"Multiple flights daily",kidInfo:"Minimum age 5, minimum 50 lbs. The 5.5-year-old may qualify. 3.5-year-old can enjoy the boat ride as observer.",tips:"Check weight/age requirements for the 5.5yo. Non-flying boat ride is fun too. Book on a clear day for best views.",region:"Waikiki",wiki:null,tags:["parasailing","flying","ocean views","tandem"]},

// ===== CULTURAL & MUSEUMS =====
{id:100,name:"Polynesian Cultural Center",category:"cultural",address:"55-370 Kamehameha Hwy, Laie",driveTime:"50 min",distance:"32 mi",description:"Six Pacific island villages with interactive activities - learn Samoan fire knife dancing, Tongan drumming, Hawaiian games. Canoe rides. Evening luau with fire knife show. Full-day experience.",cost:"Packages from ~$70-200+",hours:"Mon-Sat 12:30-9pm",kidInfo:"Very interactive - kids can participate in dancing, drumming, and games. Canoe rides are a highlight. Evening luau fire show is mesmerizing.",tips:"Full-day commitment. Buy a package that includes luau dinner. Very educational and entertaining. Worth the drive.",region:"North Shore",wiki:"Polynesian_Cultural_Center",tags:["cultural","interactive","luau","fire show","full day"]},
{id:101,name:"Pearl Harbor National Memorial",category:"cultural",address:"1 Arizona Memorial Pl",driveTime:"30 min",distance:"16 mi",description:"USS Arizona Memorial (free, reservations required), Battleship Missouri ($35/adult, $19/child), USS Bowfin Submarine ($15/adult, $8/child). Very educational for older kids.",cost:"Free for memorial, $8-35 for ships",hours:"Open daily 7am-5pm",kidInfo:"Young kids may get antsy on the memorial boat. Missouri and Bowfin are more engaging for little ones. Kids must be 4+ for submarine.",tips:"Free Arizona Memorial tickets go fast - reserve online well in advance. Budget 3-4 hours for the full experience.",region:"Pearl Harbor",wiki:"Pearl_Harbor",tags:["historical","wwii","memorial","educational","free"]},
{id:102,name:"Bishop Museum",category:"cultural",address:"1525 Bernice St",driveTime:"25 min",distance:"12 mi",description:"Hawaii's largest museum with interactive Science Adventure Center featuring volcano and wave simulators. Three-story exhibit halls, Hawaiian artifact collections, and planetarium shows. Perfect for a rainy day.",cost:"Adults $27.95, Kids 4-17 $19.95, under 4 free",hours:"Wed-Mon 9am-5pm",kidInfo:"Science Adventure Center is interactive and perfect for kids. Volcano and wave simulators. Planetarium shows. Under 4 free.",tips:"Great rainy day option. The Science Adventure Center alone is worth the price for kids. Allow 2-3 hours minimum.",region:"Honolulu",wiki:"Bernice_Pauahi_Bishop_Museum",tags:["museum","interactive","science","planetarium","rainy day"]},
{id:103,name:"Iolani Palace",category:"cultural",address:"364 S King St, downtown",driveTime:"25 min",distance:"11 mi",description:"The only royal palace on American soil. Guided or self-guided audio tours through the beautifully restored palace where Hawaiian royalty lived. Fascinating history.",cost:"Adults $25, Kids 5-12 $10",hours:"Tue-Sat 9am-4pm",kidInfo:"Under 5 not permitted on guided tours. Grounds are free to explore. Self-guided audio tour is better for families.",tips:"Grounds are free. Self-guided audio tour is more flexible with young kids than guided tour. Under 5 not allowed on guided tours.",region:"Downtown",wiki:"%CA%BBIolani_Palace",tags:["royal palace","historical","only in america","audio tour"]},
{id:104,name:"Byodo-In Temple",category:"cultural",address:"47-200 Kahekili Hwy, Kaneohe",driveTime:"30 min",distance:"16 mi",description:"Stunning Japanese Buddhist temple at the foot of the Ko'olau Mountains. Kids love feeding the hundreds of colorful koi fish (buy food in gift shop) and spotting wild peacocks.",cost:"Adults $5, Kids 2-12 $2",hours:"8:30am-4:30pm daily",kidInfo:"Kids love feeding the koi fish and chasing peacocks. Buy fish food at the gift shop. Stunning mountain backdrop.",tips:"Combine with Hoomaluhia Botanical Garden nearby. Incredibly peaceful and photogenic. Fish food is just $1-2.",region:"Windward",wiki:"Byodo-In_Temple_(Hawaii)",tags:["temple","koi fish","peacocks","mountains","photogenic"]},
{id:105,name:"Honolulu Fire Department Museum",category:"cultural",address:"620 South St",driveTime:"25 min",distance:"11 mi",description:"FREE admission! Kids get plastic fire hats and pencils, and dress up as firefighters. Guided tours by real firefighters (30-40 min). Free CPR training available next door.",cost:"Free",hours:"3rd Saturday of each month, 9am-2pm",kidInfo:"Kids dress up as firefighters and get plastic hats. Real firefighters give tours. Perfect for the 3-5 age range.",tips:"ONLY open 3rd Saturday of each month. Reserve online. Free CPR training next door. One of the best free kids activities.",region:"Honolulu",wiki:null,tags:["free","firefighters","dress up","monthly event","reserve online"]},
{id:106,name:"Pacific Aviation Museum",category:"cultural",address:"Ford Island, Pearl Harbor",driveTime:"30 min",distance:"16 mi",description:"WWII aircraft displayed in original hangars on Ford Island. Flight simulators that kids love, plus combat flight simulator. Real warplanes in authentic settings.",cost:"Adults $25, Kids $15",hours:"Open daily 9am-5pm",kidInfo:"Flight simulators are a huge hit with kids. Real WWII planes are impressive even for young ones.",tips:"Located on Ford Island - accessed through Pearl Harbor. The flight simulators alone are worth the visit for kids.",region:"Pearl Harbor",wiki:"Pearl_Harbor_Aviation_Museum",tags:["aviation","wwii","flight simulator","hangars"]},
{id:107,name:"Hawaiian Railway Society",category:"cultural",address:"91-1001 Renton Rd, Ewa Beach",driveTime:"35 min",distance:"22 mi",description:"90-minute vintage train ride along the leeward coast with an ice cream stop at the turnaround. Kids who love trains will be in absolute heaven.",cost:"Adults $15, Kids 2-12 $10",hours:"Sat 3pm, Sun 1pm & 3pm",kidInfo:"Train-loving kids will be in heaven. 90-minute ride with ice cream stop. Ages 2-12 pricing.",tips:"Only runs Saturday and Sunday. Book the Sunday 1pm ride to have afternoon free. The coastal scenery is beautiful.",region:"West Oahu",wiki:null,tags:["train","vintage","coastal ride","ice cream stop"]},
{id:108,name:"21 Degrees Estate Cacao Farm",category:"cultural",address:"47-546D Mapele Pl, Kaneohe",driveTime:"25 min",distance:"14 mi",description:"'Tree to Bar' guided tour of a boutique cacao farm. Walk through cacao trees, extensive chocolate tasting. PLUS mini-goats and bunnies for kids to pet! 2-2.5 hours.",cost:"Adults $60, Kids 3-12 $18, under 2 free",hours:"Tue/Fri/Sat 10:30am",kidInfo:"Mini-goats and bunnies to pet! Chocolate tasting. Kids 3-12 are $18. Interactive and educational.",tips:"Book in advance - limited tours. The mini-goats alone are worth it for kids. Extensive chocolate tasting for adults.",region:"Windward",wiki:null,tags:["chocolate","farm tour","mini-goats","tasting","interactive"]},
{id:109,name:"Manoa Chocolate Factory",category:"cultural",address:"Kailua",driveTime:"25 min",distance:"12 mi",description:"Bean-to-bar chocolate factory tour with extensive tasting. Hawaii is the only US state where cacao grows commercially. 45-60 minute experience.",cost:"Adults $25, Kids 5-12 $15",hours:"By reservation",kidInfo:"Kids 5-12 welcome. Extensive chocolate tasting. Educational about cacao growing.",tips:"Reservations required. Hawaii is the only US state growing cacao. Great rainy day activity.",region:"Windward",wiki:null,tags:["chocolate","factory tour","tasting","reservation required"]},
{id:110,name:"Hawaii's Plantation Village",category:"cultural",address:"94-695 Waipahu St, Waipahu",driveTime:"30 min",distance:"18 mi",description:"Open-air museum of 25 historical buildings telling the story of Hawaii's sugar plantation era and immigrant communities. Guided tours by local storytellers bring history alive.",cost:"Adults $13, Kids 4-11 $5, under 3 free",hours:"Mon-Sat 10am-2pm",kidInfo:"Under 3 free. Local storytellers make history engaging. Open-air format keeps kids from feeling trapped.",tips:"Guided tours are much better than self-guided - the storytellers are incredible. Budget 1.5-2 hours.",region:"West Oahu",wiki:null,tags:["plantation history","open-air museum","storytellers","immigration"]},

// ===== KIDS & FAMILY =====
{id:120,name:"Hawaii Children's Discovery Center",category:"family",address:"111 Ohe St",driveTime:"20 min",distance:"10 mi",description:"38,000 sq ft interactive museum designed for young kids. Tot Spot for under-5s, pretend Hawaiian Airlines cockpit, shave ice shop, fire truck, water play zone. Perfect for your kids' ages.",cost:"Check website for current pricing",hours:"Tue-Fri 9am-1pm, Sat 10am-3pm",kidInfo:"Tot Spot designed specifically for under-5s. Pretend play stations (airplane, store, fire truck). Water play zone.",tips:"Perfect for rainy days. The Tot Spot is ideal for the 3-year-old. Bring a change of clothes for water play. Allow 2-3 hours.",region:"Honolulu",wiki:null,tags:["interactive museum","tot spot","pretend play","water play","rainy day"]},
{id:121,name:"Honolulu Zoo",category:"family",address:"151 Kapahulu Ave, Waikiki",driveTime:"18 min",distance:"8 mi",description:"42-acre tropical zoo with playground and splash pad. Tropical animals in a beautiful setting near Waikiki. Some twilight tour evenings available for a unique experience.",cost:"Adults $19, Kids 3-12 $11, under 3 free",hours:"10am-4pm daily",kidInfo:"Playground and splash pad on site. Under 3 free. Good size for young kids - not overwhelming.",tips:"Combine with Kapiolani Park picnic. The splash pad is a hit on hot days. Twilight tours are magical if available.",region:"Waikiki",wiki:"Honolulu_Zoo",tags:["zoo","playground","splash pad","animals"]},
{id:122,name:"Waikiki Aquarium",category:"family",address:"2777 Kalakaua Ave, Waikiki",driveTime:"18 min",distance:"8 mi",description:"Small but excellent aquarium with monk seals, reef fish, jellyfish gallery, and a touch pool where kids can handle sea creatures. Small enough for short attention spans.",cost:"Adults $12, Kids 4-12 $5, under 4 free",hours:"9am-4:30pm daily",kidInfo:"Touch pool is the highlight - kids handle real sea creatures. Small enough for short attention spans. Under 4 free.",tips:"Small and manageable - perfect for young kids. The jellyfish gallery is mesmerizing. Combine with Kapiolani Park.",region:"Waikiki",wiki:"Waikiki_Aquarium",tags:["aquarium","touch pool","jellyfish","monk seals","small"]},
{id:123,name:"Sea Life Park",category:"family",address:"41-202 Kalanianaole Hwy, Waimanalo",driveTime:"15 min",distance:"7 mi",description:"Marine park very close to home with dolphin shows, sea lion encounters, penguin habitat, and bird sanctuary. Multiple dolphin interaction options available separately.",cost:"Kids 3 & under free, military pricing available",hours:"10am-4pm (closed Tuesdays)",kidInfo:"Kids 3 & under free. Dolphin shows, sea lions, penguins. Close to home for easy half-day trips.",tips:"Very close to home - one of your most convenient attractions. Closed Tuesdays. Military pricing available: adults $24.99, kids $19.99.",region:"East Oahu",wiki:"Sea_Life_Park_Hawaii",tags:["marine park","dolphins","penguins","close to home"]},
{id:124,name:"Kids City Adventure",category:"family",address:"1200 Ala Moana Blvd, Ward Centre",driveTime:"20 min",distance:"10 mi",description:"30,000 sq ft indoor playground! Ages 10 months to 13 years. Toddler bounce, zip line, tube slide, pretend play, interactive AR wall. Hours of entertainment for any weather.",cost:"Check website for current pricing",hours:"Mon-Thu 10am-8pm, Fri-Sat 9am-9pm, Sun 9am-8pm",kidInfo:"Ages 10 months to 13 years. Dedicated toddler area. Zip line, tube slides, AR wall. Indoor paradise.",tips:"Best rainy day option. Can easily spend 3+ hours here. The toddler area keeps the 3-year-old separate from big kids.",region:"Honolulu",wiki:null,tags:["indoor playground","rainy day","toddler area","zip line","AR wall"]},
{id:125,name:"Tropics Mini Golf",category:"family",address:"98-1101 Moanalua Rd, Aiea",driveTime:"30 min",distance:"16 mi",description:"#1 rated mini golf on Oahu. 18 interactive holes across two football fields with tropical vegetation and a faux volcano. On-site restaurant.",cost:"Adults $15, Kids 3-11 $10, under 3 free",hours:"Open daily",kidInfo:"Under 3 free. 18 interactive holes with tropical theme. Great for the 5-year-old, fun for the 3-year-old too.",tips:"Best mini golf on the island. The faux volcano is a highlight. On-site restaurant for after the round.",region:"Central Oahu",wiki:null,tags:["mini golf","interactive","volcano","top-rated"]},
{id:126,name:"Dole Plantation",category:"family",address:"64-1550 Kamehameha Hwy, Wahiawa",driveTime:"40 min",distance:"25 mi",description:"World's largest maze that kids go crazy for, Pineapple Express train ride, and plantation garden tour. Free to enter grounds and shop. Don't forget the Dole Whip!",cost:"Maze: Adults $8, Kids $6. Train: Adults $12, Kids $10. Free to enter.",hours:"9:30am-5:30pm daily",kidInfo:"World's largest maze! Pineapple Express train ride. Dole Whip is iconic. Free to enter grounds.",tips:"The maze alone is worth the trip for kids. Dole Whip is a must. Free to browse the grounds and shop. Can combine with Wahiawa Botanical Garden.",region:"Central Oahu",wiki:"Dole_Plantation",tags:["maze","train ride","dole whip","pineapple","free entry"]},
{id:127,name:"Kahuku Farms",category:"family",address:"56-800 Kamehameha Hwy, Kahuku",driveTime:"55 min",distance:"36 mi",description:"Family-owned farm with tractor wagon tours (90 min, Fri-Sun). Tropical fruit tasting, chocolate from farm-grown cacao. Cafe with smoothies, acai bowls, and paninis.",cost:"Grand Wagon Tour: Adults $50-75, Kids $40-50. Cafe items $5-15.",hours:"11am-4pm (closed Tue/Wed)",kidInfo:"Tractor wagon tours are a hit with kids. Tropical fruit tasting. Farm cafe is excellent.",tips:"Book wagon tour in advance (Fri-Sun only). The cafe smoothies ($5.25) and acai bowls ($10) are great even without the tour.",region:"North Shore",wiki:null,tags:["farm tour","tropical fruit","tractor ride","chocolate","cafe"]},
{id:128,name:"Green World Coffee Farm",category:"family",address:"71-101 Kamehameha Hwy, Wahiawa",driveTime:"40 min",distance:"25 mi",description:"Completely FREE tours and coffee sampling. Walk through coffee trees, see the roasting process, pet wild chickens roaming the grounds. No reservations needed.",cost:"Free",hours:"Open daily",kidInfo:"Free to visit. Kids love the chickens roaming the grounds. Walk through the coffee trees.",tips:"Completely free - no catch. Great stop to combine with Dole Plantation (nearby). Free coffee sampling for adults.",region:"Central Oahu",wiki:null,tags:["free","coffee farm","chickens","no reservation","educational"]},

// ===== NATURE & SCENIC =====
{id:140,name:"Halona Blowhole Lookout",category:"nature",address:"Kalanianaole Hwy",driveTime:"10 min",distance:"5 mi",description:"Watch seawater explode up through an ancient lava tube! Free roadside lookout. Green sea turtles often visible in the water below. Halona Beach Cove accessible below.",cost:"Free",hours:"Open daily",kidInfo:"Kids are mesmerized by the blowhole eruptions. Quick roadside stop. Free.",tips:"Best when surf is up - bigger blowhole eruptions. Quick stop on the way to/from many east side activities. Look for turtles below.",region:"East Oahu",wiki:"Halona_Blowhole",tags:["blowhole","free","quick stop","turtles","roadside"]},
{id:141,name:"Lanai Lookout",category:"nature",address:"Kalanianaole Hwy",driveTime:"8 min",distance:"4 mi",description:"Stunning coastal viewpoint with dramatic cliffs and ocean views. On a clear day you can see the islands of Molokai and Lanai. Quick free roadside stop.",cost:"Free",hours:"Open daily",kidInfo:"Quick stop - kids can enjoy the views without a commitment. Free.",tips:"Quick free stop on the coastal drive. Beautiful photos. Close to Halona Blowhole - do both.",region:"East Oahu",wiki:null,tags:["lookout","free","quick stop","ocean views"]},
{id:142,name:"Makapuu Lookout",category:"nature",address:"Kalanianaole Hwy",driveTime:"15 min",distance:"7 mi",description:"Panoramic views of the windward coast, Rabbit Island, and Manana Island. One of Oahu's best whale watching spots in winter (Dec-April). Free roadside stop.",cost:"Free",hours:"Open daily",kidInfo:"Quick stop with amazing views. Whale watching in March! Free.",tips:"Prime whale watching spot in March - bring binoculars. Different from the Lighthouse Trail - this is just a pullover viewpoint.",region:"East Oahu",wiki:null,tags:["lookout","whale watching","panoramic","free","quick stop"]},
{id:143,name:"Laniakea Beach (Turtle Beach)",category:"nature",address:"Kamehameha Hwy, North Shore",driveTime:"50 min",distance:"32 mi",description:"Around 30 Hawaiian green sea turtles regularly bask on this beach. Volunteer 'turtle ambassadors' educate visitors. Stay 10 feet away (federal law). Best time 12-3pm.",cost:"Free",hours:"Open daily, best 12-3pm",kidInfo:"Kids are fascinated by the giant turtles. Volunteer guides explain everything. Educational and free.",tips:"Highway construction through spring 2026 - parking may be affected. Stay 10 feet from turtles (federal law). Best viewing 12-3pm.",region:"North Shore",wiki:"Laniakea_Beach",tags:["sea turtles","free","educational","north shore"]},
{id:144,name:"Kakaako Waterfront Park & Wall Art",category:"nature",address:"Kakaako District",driveTime:"20 min",distance:"10 mi",description:"Amazing murals and street art throughout the Kakaako district. Great for a walking photo tour. Adjacent waterfront park has Diamond Head views. Free cultural experience.",cost:"Free",hours:"Open daily",kidInfo:"Colorful murals are fun for kids. Walking-friendly area. Waterfront park for running around.",tips:"The street art changes periodically. Great photography opportunity. Combine with Honolulu Beerworks or H Mart nearby.",region:"Kakaako",wiki:null,tags:["street art","murals","waterfront","free","photography"]},
{id:145,name:"Tantalus Round Top Loop Drive",category:"nature",address:"Round Top Dr / Tantalus Dr",driveTime:"20 min",distance:"9 mi",description:"10-mile scenic loop drive through the rainforest above Honolulu. Multiple pulloffs with panoramic views of Honolulu, Diamond Head, and the ocean. Beautiful at sunset. A local favorite.",cost:"Free",hours:"Open daily",kidInfo:"No hiking required - enjoy from the car. Multiple pulloffs for photos and views. Beautiful at sunset.",tips:"Drive it at sunset for the best experience. Multiple pulloffs to stop and enjoy views. A local favorite that tourists miss.",region:"Honolulu",wiki:null,tags:["scenic drive","rainforest","panoramic views","sunset","free"]},
{id:146,name:"Portlock Tide Pools / China Walls",category:"nature",address:"Portlock, Hawaii Kai",driveTime:"10 min",distance:"3 mi",description:"Beautiful rock formations on the ocean's edge with tide pools at low tide. Sea creatures in the pools for kids to discover. Stunning sunset spot with reflections in rock pools.",cost:"Free",hours:"Open daily, best at low tide",kidInfo:"Tide pools are fascinating for kids. SUPERVISE closely near the ocean edge. Best at low tide.",tips:"Check tide tables and go at low tide. Supervise kids very carefully near the edge. Amazing sunset photos. Close to home.",region:"East Oahu",wiki:null,tags:["tide pools","close to home","sunset","rock formations","free"]},

// ===== LOCAL EXPERIENCES =====
{id:160,name:"KCC Farmers Market",category:"local",address:"Kapiolani Community College",driveTime:"15 min",distance:"6 mi",description:"100+ vendors every Saturday morning. Highlights include Pig and the Lady banh mi, Mexican elote, BBQ abalone, Brazilian pao de queijo (GF!), fresh tropical fruit. One of Oahu's best markets.",cost:"Free entry",hours:"Saturday 7:30-11am",kidInfo:"Lots of food samples. Kids love trying tropical fruits. Stroller-friendly. Free entry.",gfInfo:"Brazilian pao de queijo is naturally GF. Many fresh fruit and grilled options.",tips:"Go early (7:30-8:30am) for best selection and smaller crowds. Bring cash. Free entry, pay for what you eat/buy.",region:"Honolulu",wiki:null,tags:["farmers market","saturday","100+ vendors","tropical fruit"]},
{id:161,name:"Free Hula Show at Kuhio Beach",category:"local",address:"Kuhio Beach, Waikiki",driveTime:"20 min",distance:"9 mi",description:"Free authentic hula performance most evenings at sunset on the beach. Live music and traditional dance with the ocean as backdrop. Magical for kids and adults alike.",cost:"Free",hours:"Most evenings at sunset",kidInfo:"Kids love the dancing and live music. Free and casual - come and go as you please. Beach setting.",tips:"Arrive early for a good spot. Combine with Kuhio Beach swimming. Magical at sunset. Check schedule as times vary.",region:"Waikiki",wiki:null,tags:["hula","free","sunset","cultural","beach"]},
{id:162,name:"Friday Night Fireworks",category:"local",address:"Hilton Hawaiian Village, Waikiki",driveTime:"20 min",distance:"10 mi",description:"Free fireworks show every Friday at 7:45pm launched from the Hilton beach. Watch from anywhere along Waikiki Beach. Kids go wild for it. A weekly Waikiki tradition.",cost:"Free",hours:"Every Friday at 7:45pm",kidInfo:"Kids go wild for fireworks. Free to watch from any beach vantage point. Arrive early for the best spot.",tips:"Arrive by 7pm for a good spot on the beach. Can also watch from Duke Kahanamoku Lagoon. Every Friday - you have 5 chances!",region:"Waikiki",wiki:null,tags:["fireworks","free","friday","weekly","waikiki"]},
{id:163,name:"Swap Meet at Aloha Stadium",category:"local",address:"99-500 Salt Lake Blvd, Aiea",driveTime:"25 min",distance:"14 mi",description:"Weekend flea market with hundreds of vendors. Locals shop for cheap aloha shirts ($5-10), produce, local snacks, handmade jewelry. Way more authentic than Waikiki shops.",cost:"Adults $3, kids free",hours:"Weekends 8am-3pm",kidInfo:"Kids free admission. Fun browsing for treats and toys. Much more authentic than tourist shops.",tips:"Go early for best selection. Bring cash. Great for cheap aloha shirts ($5-10) and souvenirs. Way more authentic than Waikiki.",region:"Central Oahu",wiki:null,tags:["flea market","weekend","affordable","souvenirs","local shopping"]},
{id:164,name:"Shave Ice Crawl",category:"local",address:"Multiple locations island-wide",driveTime:"Varies",description:"Try all the famous shave ice spots over 5 weeks and rank them: Matsumoto's (Haleiwa), Island Snow (Kailua), Uncle Clay's (Aina Haina - walking distance!), Waiola (McCully), Shimazu (Kaimuki).",cost:"$3-8 each",hours:"Varies by shop",kidInfo:"Kids love rating their favorites. Each shop has a different style. Walking distance option at Uncle Clay's.",tips:"Start with Uncle Clay's (your neighborhood) as the baseline. Matsumoto's in Haleiwa has the longest lines but is iconic. Rate them all!",region:"Island-wide",wiki:null,tags:["shave ice","crawl","comparison","island-wide","fun challenge"]},
{id:165,name:"Chinatown Exploration",category:"local",address:"Downtown Honolulu",driveTime:"25 min",distance:"11 mi",description:"Colorful markets with exotic fruits, lei stands, and dim sum restaurants. Cultural walking experience through one of America's oldest Chinatowns. Very photogenic.",cost:"Free to explore",hours:"Open daily, morning is best",kidInfo:"Colorful and stimulating for kids. Try exotic fruits. Lei stands are beautiful.",tips:"Morning is the best time. First Fridays - galleries open late with food vendors and live music. Great for a cultural experience.",region:"Chinatown",wiki:"Chinatown,_Honolulu",tags:["chinatown","cultural","markets","exotic fruits","lei"]},
{id:166,name:"Shore Fishing",category:"local",address:"Maunalua Bay Pier or Haleiwa Harbor",driveTime:"5-50 min",distance:"2 mi",description:"No fishing license needed for shore fishing in Hawaii! Grab a cheap rod from Don Quijote, buy frozen shrimp for bait, and fish off any pier. Kids love it. Essentially free.",cost:"Rod ~$15-20, bait ~$5",hours:"Anytime",kidInfo:"Kids love fishing. No license needed in Hawaii for shore fishing. Very affordable entertainment.",tips:"No license needed for shore fishing in Hawaii. Don Quijote sells cheap rods. Maunalua Bay pier is closest to home.",region:"Various",wiki:null,tags:["fishing","no license","affordable","kids activity"]},
{id:167,name:"Beach Cleanup Volunteering",category:"local",address:"Various locations",driveTime:"Varies",description:"Surfrider Foundation and 808 Cleanups organize regular beach cleanups. Great for teaching kids about ocean conservation. Meet local families. Usually Saturday mornings.",cost:"Free",hours:"Usually Saturday mornings",kidInfo:"Great for teaching kids about the ocean and conservation. Meet local families. Free.",tips:"Check @808cleanups on Instagram for schedule. Great way to give back and meet local families. Kids learn about conservation.",region:"Various",wiki:null,tags:["volunteering","beach cleanup","conservation","community","free"]},
{id:168,name:"People's Open Market",category:"local",address:"Rotating locations island-wide",driveTime:"Varies",description:"City-run farmers markets in neighborhood parks. Prices way cheaper than KCC market - this is where locals actually buy produce. Different location every day of the week.",cost:"Free entry, bring cash",hours:"Different locations daily, check honolulu.gov",kidInfo:"Educational - see where local food comes from. Casual park setting. Free entry.",tips:"Prices are significantly cheaper than KCC or grocery stores. Bring cash and reusable bags. Check schedule at honolulu.gov/parks/program/open-market.",region:"Various",wiki:null,tags:["farmers market","cheap produce","daily","local","cash only"]},
{id:169,name:"Kaimuki Third Fridays",category:"local",address:"Waialae Ave, Kaimuki",driveTime:"15 min",distance:"6 mi",description:"Monthly community event along Kaimuki's main street with merchants, food vendors, and entertainment. Family-friendly evening out in a local neighborhood.",cost:"Free",hours:"Third Friday of each month, evening",kidInfo:"Family-friendly evening event. Food vendors with kid-friendly options. Community atmosphere.",tips:"Great way to experience Kaimuki's restaurant scene. Combine with dinner at one of the many excellent restaurants on Waialae Ave.",region:"Kaimuki",wiki:null,tags:["monthly event","community","kaimuki","evening","free"]},

// ===== BREWERIES =====
{id:180,name:"Honolulu Beerworks",category:"breweries",address:"328 Cooke St, Kakaako",driveTime:"20 min",distance:"10 mi",description:"Industrial-chic taproom in a converted warehouse in Kakaako. Rotating taps, food trucks often parked outside. Spacious outdoor area that's dog-friendly and kid-tolerant.",cost:"$7-10/beer",hours:"Open daily",kidInfo:"Spacious outdoor area. Food trucks outside. Kid-tolerant during daytime hours.",tips:"In the heart of Kakaako's art/brewery district. Combine with street art walking tour. Food trucks outside mean the kids can eat while you drink.",region:"Kakaako",wiki:null,tags:["craft beer","warehouse","outdoor seating","food trucks","kakaako"]},
{id:181,name:"The Brewseum",category:"breweries",address:"901 Waimanu St, Kakaako",driveTime:"20 min",distance:"10 mi",description:"A WWII museum INSIDE a craft brewery! Kids can sit in a 1945 Ford Jeep and WWII-era Harley-Davidson. Model bomber planes overhead, military artifacts everywhere. Museum viewing free with purchase.",cost:"$7-10/beer, museum free with purchase",hours:"Open daily",kidInfo:"Kids can sit in a 1945 Ford Jeep and WWII Harley-Davidson! Model planes overhead. Museum is free with any purchase.",tips:"One-of-a-kind concept - nowhere else like it. The military artifacts are fascinating. Kids love climbing on the Jeep.",region:"Kakaako",wiki:null,tags:["brewery","wwii museum","jeep","unique concept","kid-friendly"]},
{id:182,name:"Lanikai Brewing",category:"breweries",address:"175 Hamakua Dr, Kailua",driveTime:"25 min",distance:"12 mi",description:"Windward side craft brewery with rotating beers and a relaxed taproom. Perfect post-beach stop after Kailua or Lanikai Beach.",cost:"$7-10/beer",hours:"Open daily",kidInfo:"Casual atmosphere. Good post-beach wind-down spot.",tips:"Perfect after a Kailua Beach day. Rotating selection of unique Hawaiian-inspired beers. Relaxed vibe.",region:"Windward",wiki:null,tags:["craft beer","kailua","post-beach","relaxed"]},
{id:183,name:"Beer Lab HI",category:"breweries",address:"Multiple locations",driveTime:"20 min",distance:"10 mi",description:"Experimental small-batch craft brewery with multiple locations. Beretania location has a beer garden and poke counter - great combo.",cost:"$7-10/beer",hours:"Varies by location",kidInfo:"Beretania location beer garden has more space. Poke counter for food.",tips:"Beretania location has both beer garden and poke counter. University Ave location is Mon-Thu 2-10pm, Fri 2pm-12am.",region:"Honolulu",wiki:null,tags:["experimental","small-batch","beer garden","poke"]},
{id:184,name:"Aloha Beer Company",category:"breweries",address:"700 Queen St, Kakaako",driveTime:"20 min",distance:"10 mi",description:"Rooftop bar with city views, live music some evenings, and brewery tours available. Full food menu.",cost:"$7-10/beer",hours:"Open daily",kidInfo:"Rooftop has views but check kid policy for evening hours.",tips:"Rooftop is the highlight. Live music some evenings. Brewery tours available if interested.",region:"Kakaako",wiki:null,tags:["rooftop","city views","live music","brewery tours"]},

// ===== GROCERY STORES =====
{id:200,name:"Foodland Farms Aina Haina",category:"groceries",address:"820 W Hind Dr #101",driveTime:"2 min",distance:"0.5 mi",description:"Your closest full supermarket - walking distance! Hawaii's oldest local chain in upgraded 'Farms' format. Full deli, bakery, poke counter (award-winning), local produce, prepared meals.",cost:"Standard grocery pricing",hours:"5am-11pm daily",kidInfo:"Walking distance. Poke counter is a great quick dinner option.",tips:"Your everyday store. Award-winning poke counter. 'Farms' format has better selection than standard Foodland. Open 5am-11pm.",region:"Aina Haina",wiki:null,tags:["walking distance","poke","local chain","everyday shopping"]},
{id:201,name:"Costco Hawaii Kai",category:"groceries",address:"333A Keahole St",driveTime:"8 min",distance:"3 mi",description:"Bulk groceries, gas station, and surprisingly excellent poke counter. Hawaii Costco poke rivals dedicated poke shops and is the best value on the island. Also carries sashimi-grade frozen ahi.",cost:"Membership required",hours:"Standard Costco hours",kidInfo:"Good for stocking up on snacks and bulk items for 5-week stay.",tips:"Hawaii Costco poke is famously good AND cheap (~$13-15/lb). Best value poke on the island. Stock up on snacks for 5 weeks.",region:"Hawaii Kai",wiki:null,tags:["bulk shopping","poke","gas station","best value"]},
{id:202,name:"Whole Foods Kahala",category:"groceries",address:"4211 Waialae Ave, Kahala Mall",driveTime:"12 min",distance:"4 mi",description:"Premium organic and natural grocery at Kahala Mall. Wide organic produce, bulk foods, prepared meals. Best option for gluten-free and specialty dietary items on this side of the island.",cost:"Premium pricing",hours:"Standard hours",kidInfo:"Great prepared foods for easy dinners. Best GF selection nearby.",gfInfo:"Best selection of gluten-free products in the area. Wide specialty dietary options.",tips:"Best for gluten-free and specialty items. On-site butchers do custom cuts. Staff will clean and cut fish at counter.",region:"Kahala",wiki:null,tags:["organic","gluten-free","specialty","kahala mall"]},
{id:203,name:"Don Quijote",category:"groceries",address:"801 Kaheka St",driveTime:"20 min",distance:"10 mi",description:"Japanese discount superstore open 24 HOURS. MASSIVE selection of Japanese groceries, snacks, bento, fresh sushi, household goods. A must-visit experience. Also excellent midnight poke.",cost:"Discount pricing",hours:"24 hours",kidInfo:"Kids love exploring the Japanese candy and toy aisles. Open 24 hours. A fun experience.",tips:"Open 24 hours - midnight sashimi runs! Kids love the Japanese candy aisle. Massive poke counter rivals expensive shops.",region:"Honolulu",wiki:null,tags:["japanese","24 hours","sushi","candy aisle","experience"]},
{id:204,name:"H Mart Kakaako",category:"groceries",address:"458 Keawe St",driveTime:"20 min",distance:"10 mi",description:"Korean-anchored Asian supermarket with massive selection of Korean, Japanese, and Asian groceries. THE place for Korean BBQ meats (pre-sliced and marinated). Food court upstairs.",cost:"Competitive pricing",hours:"8am-10pm daily",kidInfo:"Food court upstairs has Korean dining options. Wide variety of Asian snacks.",tips:"Best for Korean BBQ meats, banchan, and Asian ingredients. Food court upstairs for lunch. Pre-marinated meats make home BBQ easy.",region:"Kakaako",wiki:null,tags:["korean","asian","bbq meats","food court"]},

// ===== FISH & MEAT MARKETS =====
{id:220,name:"Tamashiro Market",category:"foodsources",address:"802 N King St, Kalihi",driveTime:"25 min",distance:"13 mi",description:"THE legendary Honolulu fish market, an institution for 50+ years. Pink 3-story tower. 30+ poke preparations. Buys directly from fishermen and Honolulu fish auction. If it swims in Hawaii, Tamashiro has it.",cost:"Sashimi ahi ~$20-30/lb, poke ~$18-25/lb",hours:"Mon-Sat",kidInfo:"A fascinating experience for kids to see the variety of seafood. Not a play destination but educational.",tips:"30+ poke varieties. Buys from local fishermen and the fish auction. Worth the 25-minute drive. The pink tower is a landmark.",region:"Kalihi",wiki:null,tags:["legendary","fish market","30+ poke varieties","institution"]},
{id:221,name:"Pier 38 Fish Market",category:"foodsources",address:"1135 N Nimitz Hwy",driveTime:"25 min",distance:"12 mi",description:"Located at the actual commercial fishing docks. Parent company owns 22 fishing vessels. Fish literally walks from boat to market - the closest to 'off the boat' you can get.",cost:"Sashimi ahi ~$19.95/lb",hours:"Tue-Sat 9am-4:30pm",kidInfo:"Kids can see the fishing boats at the dock. Educational about where fish comes from.",tips:"Best value for sashimi-grade ahi chunks. Fish comes directly off the boats here. Closed Sun-Mon.",region:"Honolulu",wiki:null,tags:["off the boat","commercial docks","freshest","sashimi grade"]},
{id:222,name:"Ono Seafood Kealahou",category:"foodsources",address:"501 Kealahou St #A53",driveTime:"8 min",distance:"3 mi",description:"Second location of the legendary Ono Seafood (est. 1995). Judy Sakuma's iconic sauces. Premium ahi, never frozen, made to order. 4.7 stars on Yelp. One of Oahu's most acclaimed poke shops.",cost:"$14-18/bowl",hours:"Mon-Sat",kidInfo:"Quick poke bowl stop. Close to home.",tips:"Your closest premium poke option. Hawaiian-style ahi is the gold standard. Made to order, never frozen. 8 minutes from home.",region:"East Oahu",wiki:null,tags:["premium poke","close to home","award-winning","made to order"]},
{id:223,name:"Maguro Brothers Hawaii",category:"foodsources",address:"1120 Maunakea St, Chinatown",driveTime:"25 min",distance:"11 mi",description:"Japanese-owned fish shop where quality rivals high-end omakase restaurants at market prices. Traditional Japanese-style sliced sashimi. 992 Yelp reviews. Sells out early.",cost:"Market pricing",hours:"Mon-Sat 9am-2pm",kidInfo:"Quick stop in Chinatown. Kids can see traditional fish preparation.",tips:"Go early - they sell out. Fish quality rivals expensive omakase restaurants. In the heart of Chinatown - combine with exploration.",region:"Chinatown",wiki:null,tags:["japanese","sashimi","sells out early","omakase quality"]},
{id:224,name:"Kalihi Super Meats",category:"foodsources",address:"2130 N King St #11",driveTime:"25 min",distance:"13 mi",description:"Family-owned since the 1950s, third generation. THE local go-to for marinated meats. Marinades made fresh daily using treasured family recipes. Their kalbi is legendary.",cost:"Marinated kalbi $10.89/lb",hours:"Mon-Sat",kidInfo:"Great for family BBQ supplies. The marinated meats make home cooking easy.",tips:"The kalbi here is legendary - seasoned with treasured family recipes. Their marinades are sold island-wide at Don Quijote and Tamura's. Third generation family business.",region:"Kalihi",wiki:null,tags:["marinated meats","legendary kalbi","family recipes","since 1950s"]},
{id:225,name:"Forage Hawaii",category:"foodsources",address:"1001 Dillingham Blvd #110",driveTime:"25 min",distance:"12 mi",description:"Oahu's #1 for 100% grass-fed, locally raised meat. Everything sustainably and humanely sourced from Hawaiian ranches. Wild Maui Nui venison, Big Island grass-fed beef, local pork and chicken.",cost:"Grass-fed steaks ~$25-40/lb, ground ~$10-14/lb",hours:"Check website",kidInfo:"Educational about sustainable and local food sourcing.",tips:"Order online for best selection. Also at Saturday Kakaako and Sunday Kailua farmers markets. Wild Maui Nui venison is unique to Hawaii.",region:"Honolulu",wiki:null,tags:["grass-fed","local","sustainable","venison","premium"]},
{id:226,name:"Local I'a (Community Supported Fishery)",category:"foodsources",address:"3458 Waialae Ave, Kaimuki",driveTime:"15 min",distance:"6 mi",description:"Oahu's only community-supported fishery. Fish comes directly from local small-scale fishermen - shortest supply chain possible. Walk-in retail and subscription boxes.",cost:"Market pricing, subscription available",hours:"Delivery Sun/Mon, retail varies",kidInfo:"Educational about supporting local fishermen. Can be a fun weekly ritual.",tips:"Consider a weekly CSF box subscription for your 5-week stay. Whatever the boats caught that day - great variety. Walk-in retail also available.",region:"Kaimuki",wiki:null,tags:["sustainable","local fishermen","CSF subscription","shortest supply chain"]},

// ===== EVENTS (Specific Dated) =====
{id:300,name:"Honolulu Festival - Grand Parade & Fireworks",category:"events",address:"Hawaii Convention Center + Kalakaua Ave + Waikiki Beach",driveTime:"20 min",distance:"9 mi",eventDate:"2026-03-15",description:"Hawaii's premier Pacific Rim cultural festival celebrating its 30th anniversary. Craft fair with 100+ vendors, food corners, cultural performances from across the Pacific. Grand Parade features elaborate floats along Kalakaua Ave. Night ends with spectacular Nagaoka Fireworks over Waikiki Beach.",cost:"Convention Center: $10 adult, Under 18 FREE. Parade & fireworks FREE.",hours:"Convention Center 10am-6pm, Parade 4pm, Fireworks 8:30pm",kidInfo:"Parade + fireworks are perfect for kids. Bon dance is participatory! Under 18 free at convention center.",tips:"Your arrival day spectacular! The Grand Parade along Kalakaua is the highlight. Fireworks over Waikiki at 8:30pm are world-class.",region:"Waikiki",wiki:"Honolulu_Festival",url:"https://www.honolulufestival.com/en/",tags:["festival","parade","fireworks","cultural","arrival day"]},
{id:301,name:"Honolulu Rainbow EKIDEN & Kids' Race",category:"events",address:"Kapiolani Park, Waikiki",driveTime:"18 min",distance:"8 mi",eventDate:"2026-03-15",description:"10th anniversary relay race with a fun atmosphere. Teams run 5K loops through Waikiki. Dedicated kids' race for under-12s at 10am.",cost:"Free to watch",hours:"8am start, Kids' Race 10am",kidInfo:"Dedicated kids' race for under-12s. Fun atmosphere even just to watch.",tips:"Free to watch. The kids' race at 10am is a fun activity. Same day as Honolulu Festival.",region:"Waikiki",wiki:null,tags:["running","kids race","free to watch"]},
{id:302,name:"Sea Life Park Whale Festival",category:"events",address:"41-202 Kalanianaole Hwy, Waimanalo",driveTime:"15 min",distance:"7 mi",eventDate:"2026-03-16",eventEndDate:"2026-03-22",description:"Multi-week whale festival honoring humpback whales. Artist hand-illustrates life-size humpback outlines for kids to paint and take home as free keepsake. Whale-watching from park, simulated whale detanglement, educational presentations.",cost:"Adults ~$45, Kids 3-12 ~$30, Under 3 FREE",hours:"9:30am-4pm",kidInfo:"Hands-on painting and whale activities are perfect for both ages. Free keepsake painting. Under 3 FREE.",tips:"Very close to home! Runs March 16-22. Keiki Sunday on March 22 is the finale with free child admission.",region:"East Oahu",wiki:null,url:"https://www.sealifeparkhawaii.com/discover-sea-life-park/special-events/whale-festival",tags:["whale festival","hands-on","painting","close to home","week-long"]},
{id:303,name:"St. Patrick's Day Parade (59th Annual)",category:"events",address:"Fort DeRussy to Kapiolani Park, Waikiki",driveTime:"20 min",distance:"9 mi",eventDate:"2026-03-17",description:"Bagpipers, Irish dancers, marching bands, military groups, keiki from local schools, decorated vehicles. Post-parade festival at Kapiolani Park with arts & crafts booths, food vendors, live music. ~300 participants.",cost:"Free",hours:"Parade starts at NOON, ~1.5 hours. Post-parade festival follows.",kidInfo:"Very family-friendly parade. Post-parade park festival is great for little ones.",tips:"Parade route: Fort DeRussy along Saratoga Ave & Kalakaua Ave to Kapiolani Park. Get there early for a good spot.",region:"Waikiki",wiki:null,url:"https://friendsofstpatrickhawaii.com",tags:["parade","st patricks day","family-friendly","free"]},
{id:304,name:"Waikiki Aquarium 122nd Birthday Celebration",category:"events",address:"Kapiolani Park near Waikiki Aquarium",driveTime:"18 min",distance:"8 mi",eventDate:"2026-03-19",description:"Birthday party with live entertainment, art activities with a Hawaii artist, storytelling, INFLATABLES, educational games, and birthday cake! All free.",cost:"Free",hours:"10am-12pm",kidInfo:"PERFECT for your ages. Inflatables, cake, storytelling, art activities. All free!",tips:"Free event but arrive early for best experience. Inflatables are the highlight for kids.",region:"Waikiki",wiki:null,url:"https://www.waikikiaquarium.org/",tags:["free","birthday party","inflatables","cake","kids event"]},
{id:305,name:"Third Friday Kaimuki (March)",category:"events",address:"Waialae Ave, Kaimuki",driveTime:"15 min",distance:"6 mi",eventDate:"2026-03-20",description:"Monthly community celebration with local merchants, food vendors, and entertainment along Kaimuki's main street. More family-friendly than First Friday Chinatown. Great restaurant scene.",cost:"Free",hours:"5pm-9pm",kidInfo:"Good for families. Walkable strip with food and kid-friendly activities.",tips:"Combine with dinner at one of Kaimuki's excellent restaurants. Great local neighborhood vibe.",region:"Kaimuki",wiki:null,url:"https://www.kaimukihawaii.com/d/c/third-fridays-kaimuki.html",tags:["community event","kaimuki","monthly","free","evening"]},
{id:306,name:"HFD Museum (March - 3rd Saturday)",category:"events",address:"620 South St, Honolulu",driveTime:"25 min",distance:"11 mi",eventDate:"2026-03-21",description:"Free tours by real firefighters (30-40 min). Kids get plastic hats, pencils, whistles. Dress up as firefighters, pretend-cook area. Free CPR training next door. RESERVATION REQUIRED - limit 15 per slot.",cost:"Free",hours:"9am-2pm, tours every hour, last tour 1pm",kidInfo:"PERFECT for both ages. Kids dress up as firefighters. Real firefighters give tours.",tips:"ONLY open 3rd Saturday of each month. Reserve early - 15 per slot limit. Phone: 808-723-7168.",region:"Honolulu",wiki:null,tags:["free","firefighters","dress up","reservation required","monthly"]},
{id:307,name:"Koko Marina Craft & Gift Fair",category:"events",address:"Koko Marina Center, 7192 Kalanianaole Hwy",driveTime:"5 min",distance:"2 mi",eventDate:"2026-03-21",description:"70+ vendors selling jewelry, artwork, electronics, clothing, food. Also includes Hawaii Kai Plant Exchange (10am-1pm). Right in your neighborhood!",cost:"Free",hours:"10am-2:30pm",kidInfo:"Browse-friendly with food vendors. Very close to home.",tips:"5 minutes from home! 70+ vendors. Also has a plant exchange 10am-1pm.",region:"Hawaii Kai",wiki:null,tags:["craft fair","close to home","70+ vendors","free"]},
{id:308,name:"Prince Kuhio Day Parade & Ho'olaule'a",category:"events",address:"Kalakaua Ave to Kapiolani Park",driveTime:"18 min",distance:"8 mi",eventDate:"2026-03-26",description:"State holiday! Royal Hawaiian parade with hula groups, royal societies, cultural schools, pa'u riders on horseback, floats, Royal Hawaiian Band. Post-parade at Kapiolani Park: food booths, Hawaiian arts & crafts, live performances, cultural demonstrations.",cost:"Free",hours:"Parade 10am-Noon, Festival until ~4pm",kidInfo:"Very visual parade with HORSES and floats. Cultural activities at the park afterward. Kids love the horses!",tips:"State holiday so many businesses closed. The parade is beautiful - horses, floats, hula dancers. Post-parade festival has food and crafts.",region:"Waikiki",wiki:null,url:"https://princekuhiofestival.com/",tags:["state holiday","parade","horses","hawaiian culture","free"]},
{id:309,name:"Eat the Street Food Truck Rally",category:"events",address:"555 South St, Kakaako",driveTime:"20 min",distance:"10 mi",eventDate:"2026-03-27",description:"Honolulu's biggest food truck rally! Up to 40 food trucks, live music, and KEIKI entertainment including face painting, balloon art, and WATERSLIDES. 7,000+ attendees.",cost:"Free entry, pay for food",hours:"4pm-9pm",kidInfo:"Specifically includes kid entertainment - face painting, balloon art, waterslides! 40 food trucks.",tips:"Arrive early for parking. Free entry, pay per food item. Waterslides are the highlight for kids. 7,000+ attendees so expect crowds.",region:"Kakaako",wiki:null,url:"https://eatthestreethawaii.com/eat-the-street/",tags:["food trucks","waterslides","face painting","massive event","free entry"]},
{id:310,name:"FoodieCon & Spring Expo",category:"events",address:"Neal Blaisdell Exhibition Hall, 777 Ward Ave",driveTime:"20 min",distance:"10 mi",eventDate:"2026-03-28",eventEndDate:"2026-03-29",description:"Hawaii's largest foodie convention! 200+ booths, 100+ food vendors. Sample plates $7 each. Cooking demos, workshops, packaged foods, specialty drinks, craft goods. 10,000 attendees over 2 days.",cost:"~$5 entry, food samples $7 each",hours:"Sat 10am-7pm, Sun 10am-5pm",kidInfo:"Kids love sampling food. Can be crowded - stroller helpful. Two days to spread it out.",tips:"Two-day event. Go Saturday for full selection. Bring cash. 200+ booths is a lot - plan which sections to hit.",region:"Honolulu",wiki:null,url:"https://www.pacificexpos.com/foodiecon",tags:["food convention","200+ booths","sampling","two days"]},
{id:311,name:"Pearl City Easter Egg Hunt",category:"events",address:"Momilani Community Center, Pearl City",driveTime:"25 min",distance:"14 mi",eventDate:"2026-03-28",description:"600 registered participants ages 0-11. Great prizes plus 20 golden eggs. Separate age groups ensure fair fun for all ages.",cost:"Free (registration required)",hours:"Morning",kidInfo:"Separate age groups. 20 golden eggs with prizes. Registration required.",tips:"Register in advance - 600 participant limit. Separate age groups so both kids can participate fairly.",region:"Central Oahu",wiki:null,url:"https://www.mypearlcity.com/2026/03/04/2026-pearl-city-easter-egg-hunt/",tags:["easter egg hunt","free","registration required","prizes"]},
{id:312,name:"NOAA Sanctuary Ocean Count (Whale Watch)",category:"events",address:"Multiple shore sites (Makapuu Lighthouse is closest)",driveTime:"15 min",distance:"7 mi",eventDate:"2026-03-28",description:"NOAA citizen science event - count humpback whales from shore! 30th year of this program. Feb count spotted 1,935 whales across Hawaii. Volunteer 'whale ambassadors' educate visitors.",cost:"Free",hours:"8am-12:15pm",kidInfo:"Great educational experience. Makapuu Lighthouse is close to you! Learn about whale science.",tips:"Makapuu Lighthouse is the top spot and closest to you (~15 min). Bring binoculars. Educational and free. 30th anniversary!",region:"East Oahu",wiki:null,url:"https://hawaiihumpbackwhale.noaa.gov/involved/ocean-count.html",tags:["whale watching","citizen science","NOAA","free","educational"]},
{id:313,name:"Keiki Street Festival",category:"events",address:"SALT at Our Kakaako, 685 Auahi St",driveTime:"20 min",distance:"10 mi",eventDate:"2026-03-29",description:"Block party DESIGNED FOR KIDS! Art exhibits, bamboo stamp bookmark making, free keiki fitness classes, keiki fashion show, kid art stations, MAGICIANS, games, giveaways, food treats, DJ, frozen popsicles, cupcakes, small-batch ice cream, gummy candy.",cost:"Free",hours:"10am-2pm",kidInfo:"LITERALLY DESIGNED for your kids' ages. Magicians, art stations, fashion show, popsicles, cupcakes. Everything is kid-focused.",tips:"TOP PICK! This is the #1 kid event during your stay. Everything is designed for young children. Free!",region:"Kakaako",wiki:null,url:"https://ourkakaako.com/ksf/",tags:["TOP PICK","kids festival","free","magicians","art","kakaako"]},
{id:314,name:"First Friday Chinatown Art Walk (April)",category:"events",address:"Nuuanu Ave & Hotel St, Chinatown",driveTime:"25 min",distance:"11 mi",eventDate:"2026-04-03",description:"Dozens of galleries open their doors with live music, street food, and special sales. Vibrant walkable evening. Go EARLY (5-7pm) with kids before it becomes more bar-oriented.",cost:"Free",hours:"5pm-9pm",kidInfo:"Go early (5-7pm) with kids. Later it becomes more adult-oriented. Galleries and food are the draw.",tips:"Go between 5-7pm with kids. After 7pm it gets more bar-scene. Great for art, food, and cultural experience.",region:"Chinatown",wiki:null,url:"https://firstfridayhawaii.com/",tags:["art walk","chinatown","galleries","monthly","evening"]},
{id:315,name:"Ewa Complex Easter Bash",category:"events",address:"Asing Community Park, 91-1450 Renton Rd, Ewa Beach",driveTime:"25 min",distance:"22 mi",eventDate:"2026-04-04",description:"Free community Easter celebration with egg hunt, arts & crafts, and carnival games for kids.",cost:"Free",hours:"Starting 9am",kidInfo:"Egg hunt, arts & crafts, carnival games. Free and designed for young kids.",tips:"Free community event. Arrive early for the egg hunt. Good option if you're on the west side that day.",region:"West Oahu",wiki:null,tags:["easter","egg hunt","free","carnival games"]},
{id:316,name:"Easter Sunrise Service at Punchbowl",category:"events",address:"National Memorial Cemetery, 2177 Puowaina Dr",driveTime:"15 min",distance:"8 mi",eventDate:"2026-04-05",description:"Century-old tradition. Thousands gather at Punchbowl Crater for sunrise service with choirs, bands, and sermon. Breathtaking views overlooking Honolulu at dawn.",cost:"Free",hours:"~6am",kidInfo:"Early start (6am) may be tough for young kids. Beautiful setting if they're awake.",tips:"Arrive well before 6am for parking. Century-old tradition. Stunning views of Honolulu at sunrise. Dress warmly for early morning.",region:"Honolulu",wiki:"National_Memorial_Cemetery_of_the_Pacific",tags:["easter","sunrise","tradition","panoramic views","free"]},
{id:317,name:"HEART of Honolulu Art Street Festival",category:"events",address:"Nuuanu Ave, Chinatown (between King & Beretania)",driveTime:"20 min",distance:"10 mi",eventDate:"2026-04-11",description:"Street CLOSED to traffic, opened to pedestrians! Art, live music, food vendors, creative local vendors, performances. 4th annual edition. Very family-friendly daytime event.",cost:"Free",hours:"11am-4pm",kidInfo:"Pedestrian-only streets are safe for kids. Art activities and performances. Daytime family-friendly event.",tips:"Car-free streets are great with young kids. Food vendors, art, and live performances. 4th annual edition.",region:"Chinatown",wiki:null,url:"https://www.downtownarthi.org/heartofhonolulufestival",tags:["street festival","car-free","art","family-friendly","free"]},
{id:318,name:"Easter Egg Hunts Galore (April 12)",category:"events",address:"Multiple locations",driveTime:"Varies",eventDate:"2026-04-12",description:"Pick from 5+ Easter egg hunts on this day: Manoa Marketplace Eggstravaganza (free, 10am), Spring Fling at Children's Discovery Center ($15, 1pm), La Keiki at Royal Hawaiian Center (free, 2pm), Joy of Easter at Mililani (free petting zoo & pony rides, 10am), Town Center Mililani (free bunny photos, 10am).",cost:"Free to $15 depending on event",hours:"Various, mostly morning",kidInfo:"Multiple age-appropriate options. Mililani has petting zoo AND pony rides! Royal Hawaiian Center has candy lei making.",tips:"Pick one or try to hit two! Manoa Marketplace and Royal Hawaiian Center are closest. Mililani has the best extras (petting zoo, pony rides) but is 30 min drive.",region:"Various",wiki:null,tags:["easter","egg hunt","multiple options","petting zoo","pony rides"]},
{id:319,name:"Hapalua - Hawaii's Half Marathon",category:"events",address:"Starts at Duke Kahanamoku statue, Waikiki",driveTime:"Watch from home area",distance:"2 mi",eventDate:"2026-04-12",description:"13.1 mile race with no time limit. Route runs through Diamond Head, Kahala, and near your Aina Haina neighborhood! Watch from the sidewalk as runners pass by.",cost:"Free to watch",hours:"6am start",kidInfo:"Watch from your neighborhood sidewalk! Runners pass near Aina Haina. Fun to cheer.",tips:"The route passes near your rental - watch from the sidewalk! Free spectating. Early 6am start.",region:"Near home",wiki:null,url:"https://www.thehapalua.com/",tags:["marathon","free to watch","near home","spectating"]},
{id:320,name:"Sea Life Park Springtime Celebration & Egg Hunt",category:"events",address:"Sea Life Park, 41-202 Kalanianaole Hwy",driveTime:"15 min",distance:"7 mi",eventDate:"2026-04-13",description:"Easter Egg Scavenger Hunt with stamp cards and prizes through park habitats. Kids follow clues and collect stamps at different animal exhibits.",cost:"Free keiki admission with paid adult",hours:"10am-4pm",kidInfo:"Scavenger hunt through the park. Kids follow clues and collect stamps. Free child admission with adult.",tips:"Close to home! Free child admission with paid adult. The scavenger hunt format keeps kids engaged through the whole park.",region:"East Oahu",wiki:null,tags:["easter","scavenger hunt","close to home","free kids"]},
{id:321,name:"Third Friday Kaimuki (April)",category:"events",address:"Waialae Ave, Kaimuki",driveTime:"15 min",distance:"6 mi",eventDate:"2026-04-17",description:"Monthly community celebration along Kaimuki's restaurant row. Local merchants, food vendors, entertainment, family activities.",cost:"Free",hours:"5pm-9pm",kidInfo:"Family-friendly evening event with food and activities.",tips:"Second chance to experience Kaimuki Third Fridays if you missed March's edition.",region:"Kaimuki",wiki:null,tags:["community event","kaimuki","monthly","free"]},
{id:322,name:"Panji and the Lost Princess - Shadow Puppetry",category:"events",address:"Kennedy Theatre, UH Manoa, 1770 East-West Rd",driveTime:"15 min",distance:"7 mi",eventDate:"2026-04-17",eventEndDate:"2026-04-18",description:"Giant Balinese shadow puppetry with live gamelan music, actors, and dancers. Traditional Javanese tale. 'Suitable for all ages.' MAGICAL for children - giant colorful shadow puppets, exotic music, dramatic lighting.",cost:"Check UH box office",hours:"7:30pm (both nights)",kidInfo:"Magical for children - giant shadow puppets are mesmerizing. 'Suitable for all ages.' 7:30pm start may be late for young kids.",tips:"TOP PICK for a unique cultural experience! 7:30pm start - consider if kids can handle a late show. Two performances (Fri & Sat).",region:"Honolulu",wiki:null,url:"https://manoa.hawaii.edu/liveonstage/panji/",tags:["TOP PICK","shadow puppetry","magical","cultural","gamelan"]},
{id:323,name:"Keiki Rainbow Run",category:"events",address:"Kakaako Waterfront Park",driveTime:"20 min",distance:"10 mi",eventDate:"2026-04-18",description:"1.3-mile fun run for children! Wellness Fair + Active Zone with engaging activities. Finishers get t-shirt and healthy snacks. Categories: ages 5-12, ages 13+, age 4 & under/strollers, and virtual. Limited to 1,600 participants.",cost:"Registration required (deadline April 17 noon)",hours:"Warm-ups 8am, Race 8:30am",kidInfo:"Your 5.5-year-old can RUN in the 5-12 category! Your 3.5-year-old can do the stroller category! T-shirt and snacks for finishers.",tips:"TOP PICK! Register before April 17 noon deadline. 1,600 participant limit. Both kids can participate in different categories.",region:"Kakaako",wiki:null,url:"https://runsignup.com/Race/HI/Honolulu/KeikiRainbowRu",tags:["TOP PICK","kids run","registration required","t-shirt","active"]},
{id:324,name:"HFD Museum (April - 3rd Saturday)",category:"events",address:"620 South St, Honolulu",driveTime:"25 min",distance:"11 mi",eventDate:"2026-04-18",description:"Second chance this trip! Free tours by real firefighters. Kids dress up as firefighters, get plastic hats and pencils. Reserve early - only 15 per slot.",cost:"Free",hours:"9am-2pm",kidInfo:"If you missed March 21, here's your second chance! Same great firefighter experience.",tips:"Reserve early - same 15-per-slot limit. Phone: 808-723-7168.",region:"Honolulu",wiki:null,tags:["free","firefighters","monthly","reservation required"]},
{id:325,name:"Easter Festival in Hawaii Kai",category:"events",address:"Hawaii Kai Towne Center, 333 Keahole St",driveTime:"5 min",distance:"2 mi",eventDate:"2026-04-19",description:"Easter Bunny selfie station (bring camera/phone), twisted balloon animals, Easter prize giveaways. RIGHT IN YOUR NEIGHBORHOOD on your departure day!",cost:"Free",hours:"1pm-5pm",kidInfo:"Balloon animals and Easter Bunny photos. Right in your neighborhood!",tips:"5 minutes from home on your departure day! Perfect last activity. Bring your own camera for Easter Bunny photos.",region:"Hawaii Kai",wiki:null,url:"https://hawaiikaitownecenter.com/event/hktc-easter-festival/",tags:["easter","close to home","departure day","free","balloon animals"]},
{id:326,name:"Honolulu Museum of Art - Free Family Sunday",category:"events",address:"900 S Beretania St",driveTime:"20 min",distance:"10 mi",eventDate:"2026-04-19",description:"Free admission (normally $20 adult) plus special family art activities and kid programming. Great way to end your trip with culture.",cost:"Free",hours:"Check museum hours",kidInfo:"Free admission. Special family programming and kid art activities.",tips:"Normally $20 adult admission - free on this day! Special kid programming. Nice final cultural experience.",region:"Honolulu",wiki:"Honolulu_Museum_of_Art",tags:["free admission","art","family programming","departure day"]},
{id:327,name:"UH Rainbow Warriors Baseball",category:"events",address:"Les Murakami Stadium, UH Manoa",driveTime:"15 min",distance:"7 mi",eventDate:"2026-03-25",description:"College baseball in a relaxed outdoor stadium. UH vs Hawaii Pacific (Mar 25), UH vs Cal State Fullerton (Mar 27-29). Casual, affordable evening entertainment.",cost:"~$10-15 general admission",hours:"6:35pm (evening games), 1:05pm (Sunday)",kidInfo:"Relaxed outdoor stadium. Good for a casual evening out. Kids can run around.",tips:"Affordable evening entertainment. Sunday 1:05pm game is best timing for young kids. Relaxed atmosphere.",region:"Honolulu",wiki:null,tags:["baseball","college","evening","casual","affordable"]},

// ===== LUAUS =====
{id:340,name:"Toa Luau (Best for Families)",category:"luaus",address:"Waimea Valley, Haleiwa",driveTime:"45 min",distance:"30 mi",description:"Most intimate luau setting at Waimea Valley. Huge lawn where kids run freely during the show. Includes 7-day Waimea Valley admission (waterfall!). Kava ceremony. Not overwhelming like larger luaus.",cost:"Adults from $135, Ages 2-7 $45, Under 2 FREE. Code TOALUAU10 for up to 31% off.",hours:"Mon-Fri, check-in 4:50pm, ends ~8pm",kidInfo:"BEST FOR FAMILIES. Huge lawn for kids to run. Includes 7-day Waimea Valley pass. Intimate setting is less overwhelming for young kids.",tips:"Use discount code TOALUAU10 for up to 31% off! The 7-day Waimea Valley admission is a huge bonus - visit the waterfall another day.",region:"North Shore",wiki:null,url:"https://www.toaluau.com/",tags:["BEST FOR FAMILIES","luau","intimate","waimea valley","discount code"]},
{id:341,name:"Experience Nutridge (Most Intimate)",category:"luaus",address:"Nutridge Estate, Tantalus",driveTime:"20 min",distance:"9 mi",description:"Only 50-75 people per event. 'Backyard luau' feel on a private estate above Honolulu. Kids roast sweet potatoes over the fire. TripAdvisor #1 rated luau on Oahu.",cost:"Adults $159, Kids 4-12 $100, Under 3 FREE",hours:"Sun-Fri, 4-8pm",kidInfo:"Only 50-75 guests means personal attention. Kids roast sweet potatoes. Not overwhelming. Under 3 FREE.",tips:"TripAdvisor #1 luau on Oahu. The intimate size is perfect for families with young kids. Book well in advance.",region:"Honolulu",wiki:null,url:"https://experiencenutridge.com/",tags:["#1 rated","intimate","50-75 guests","sweet potatoes","tantalus"]},
{id:342,name:"KA WA'A at Disney Aulani (Best Production)",category:"luaus",address:"Aulani Resort, Ko Olina, Kapolei",driveTime:"45 min",distance:"28 mi",description:"Disney-level production quality. Pre-dinner activities include Hawaiian tattoos and lei-making. Extensive kid buffet. Gratuity included. Open to non-guests. If your kids love Disney, this is the one.",cost:"Adults $190, Kids 3-9 $119, Under 3 FREE",hours:"Tue/Wed/Fri/Sat",kidInfo:"Disney-level production. Extensive kid buffet. Pre-dinner lei-making and Hawaiian tattoo activities. Open to non-guests.",tips:"Best production value. Book well in advance as Disney events sell out. Combine with Ko Olina Lagoons visit (same area).",region:"West Oahu",wiki:null,url:"https://www.disneyaulani.com/activities/luau/",tags:["disney","best production","kid buffet","lei making","premium"]},
{id:343,name:"Chief's Luau (Most Interactive)",category:"luaus",address:"Wet 'n' Wild Hawaii, Kapolei",driveTime:"45 min",distance:"28 mi",description:"Chief Sielu (world champion fire knife dancer) brings kids ON STAGE to dance! Pre-show includes hula lessons, lei-making, and spear throwing for kids. Very interactive and entertaining.",cost:"Adults from $182, Kids 5-12 $129, Under 5 FREE",hours:"Sun/Mon/Wed/Thu/Fri, check-in 5pm, ends ~8:30pm",kidInfo:"Kids get brought ON STAGE to dance with the chief! Pre-show hula lessons and spear throwing. Under 5 FREE. Very interactive.",tips:"Most interactive luau - kids are part of the show. Chief Sielu is a world champion fire knife dancer. Under 5 is FREE.",region:"West Oahu",wiki:null,url:"https://chiefsluauhawaii.com/",tags:["most interactive","on stage","fire knife","spear throwing","free under 5"]},
{id:344,name:"Aloha Kai Luau at Sea Life Park (Closest)",category:"luaus",address:"Sea Life Park, Waimanalo",driveTime:"15 min",distance:"7 mi",description:"Closest luau to your house! Includes multi-day Sea Life Park admission pass. Oceanfront setting. Good option if you want convenience without a long drive.",cost:"Adults from $135, Kids 4-12 $111, Under 3 FREE",hours:"Mon/Wed/Thu/Fri/Sun, check-in 4:30pm, ends ~8:15pm",kidInfo:"Closest luau to home (15 min). Includes Sea Life Park multi-day pass. Under 3 FREE.",tips:"15 minutes from home! The multi-day Sea Life Park pass is a great bonus. Best option for convenience.",region:"East Oahu",wiki:null,url:"https://www.alohakailuau.com/",tags:["closest luau","sea life park pass","convenient","oceanfront"]},

// ===== RECURRING WEEKLY EVENTS =====
{id:360,name:"Kilohana Hula Show",category:"events",address:"Waikiki Shell, Kapiolani Park",driveTime:"18 min",distance:"8 mi",recurring:"Sun-Thu",description:"Free morning hula show at the Waikiki Shell in beautiful Kapiolani Park. Authentic Hawaiian hula with live music. Runs Sunday through Thursday every week.",cost:"Free",hours:"9:30-10:30am",kidInfo:"Free hula show in a park setting. Kids enjoy the music and dancing. Morning timing works well.",tips:"Great way to start a Waikiki day. Free and casual - come and go as you please. Combine with zoo or aquarium.",region:"Waikiki",wiki:null,tags:["recurring","hula","free","morning","weekly"]},
{id:361,name:"Royal Hawaiian Center Free Classes",category:"events",address:"Royal Hawaiian Center, Waikiki",driveTime:"20 min",distance:"9 mi",recurring:"Mon-Fri (various)",description:"Free cultural classes throughout the week: Ukulele (Mon 11am), Hula Lesson (Tue 11am), Lau Hala Weaving (Wed noon), Keiki Hula (Thu noon), Lei-Making (Fri noon). All free!",cost:"Free",hours:"Various, see schedule",kidInfo:"Keiki Hula class on Thursdays at noon is designed for kids. Lei-making on Fridays is great for all ages.",tips:"All classes are free at the Royal Hawaiian Center. The Keiki Hula (Thu) and Lei-Making (Fri) are best for your kids' ages.",region:"Waikiki",wiki:null,tags:["recurring","free classes","hula","ukulele","lei making","weekly"]},
{id:362,name:"Kuhio Beach Hula Show",category:"events",address:"Kuhio Beach, Waikiki",driveTime:"20 min",distance:"9 mi",recurring:"Tue & Sat",description:"Authentic evening hula show right on the beach at sunset. Live music, traditional and modern hula. One of the most magical free experiences in Waikiki. Tuesdays and Saturdays.",cost:"Free",hours:"6:30-7:30pm",kidInfo:"Magical sunset setting. Kids love the dancing. Free and casual - beach setting means they can play nearby.",tips:"Arrive early for a good spot. The sunset backdrop is incredible. Every Tuesday and Saturday during your stay.",region:"Waikiki",wiki:null,tags:["recurring","hula","sunset","free","beach","weekly"]},
{id:363,name:"Aina Haina Library Story Time",category:"events",address:"5246 Kalanianaole Hwy",driveTime:"2 min",distance:"0.3 mi",recurring:"Thursday",description:"Free keiki story time at your neighborhood library - walking distance! Perfect for a low-key Thursday morning. Free library card available for visitors (bring ID + local address).",cost:"Free",hours:"10:30am every Thursday",kidInfo:"Designed for young children. Walking distance from home! Free library card available for visitors.",tips:"Walking distance! Bring ID + your rental address to get a free library card. Great for a low-key morning routine.",region:"Aina Haina",wiki:null,tags:["recurring","free","story time","walking distance","weekly","thursday"]},
{id:364,name:"Hilton Friday Night Fireworks",category:"events",address:"Hilton Hawaiian Village, Waikiki Beach",driveTime:"20 min",distance:"10 mi",recurring:"Friday",description:"Free fireworks show every Friday at 7:45pm from the Hilton beach. Watch from anywhere along Waikiki Beach. A weekly Waikiki tradition that kids absolutely love. You have 5 Fridays!",cost:"Free",hours:"Every Friday at 7:45pm",kidInfo:"Kids go wild for fireworks. Free to watch from the beach. 5 chances during your stay!",tips:"Arrive by 7pm for a good beach spot. Can also watch from Duke Kahanamoku Lagoon. You have 5 Fridays to catch this!",region:"Waikiki",wiki:null,tags:["recurring","fireworks","free","friday","weekly"]},
{id:365,name:"KCC Saturday Farmers Market",category:"events",address:"Kapiolani Community College",driveTime:"15 min",distance:"6 mi",recurring:"Saturday",description:"Oahu's premier farmers market with 100+ vendors every Saturday morning. Local produce, prepared foods, crafts. Highlights: banh mi, elote, BBQ abalone, pao de queijo (GF!), tropical fruit.",cost:"Free entry",hours:"Every Saturday 7:30-11am",kidInfo:"Lots of food samples and tropical fruits for kids. Stroller-friendly. 5 Saturdays during your stay.",gfInfo:"Brazilian pao de queijo is naturally GF. Many fresh fruit and grilled options available.",tips:"Go early (7:30-8:30am) for best selection. Bring cash and reusable bags. 5 Saturdays to try different vendors each week!",region:"Honolulu",wiki:null,tags:["recurring","farmers market","saturday","100+ vendors","weekly"]},
{id:366,name:"Royal Hawaiian Band at Iolani Palace",category:"events",address:"Iolani Palace grounds, 364 S King St",driveTime:"25 min",distance:"11 mi",recurring:"Friday",description:"Free concert by the Royal Hawaiian Band on the grounds of Iolani Palace every Friday at noon. Beautiful music in a historic setting. The band has been performing since 1836!",cost:"Free",hours:"Every Friday 12-1pm",kidInfo:"Short concert (1 hour) in a park setting. Kids can play on the palace grounds during music.",tips:"Combine with an Iolani Palace tour. Free music in a stunning historic setting. The band has performed since 1836!",region:"Downtown",wiki:"Royal_Hawaiian_Band",tags:["recurring","free","concert","historic","friday","weekly"]},
{id:367,name:"Ala Moana Center Hula Shows",category:"events",address:"Ala Moana Center, Centerstage",driveTime:"20 min",distance:"10 mi",recurring:"Daily + Sun Keiki",description:"Daily hula show at 5pm at Ala Moana Centerstage. Special Keiki Hula Show on Sundays at 1pm featuring young performers. Free and right in the mall.",cost:"Free",hours:"Daily 5pm, Sunday Keiki Show 1pm",kidInfo:"Sunday 1pm Keiki Hula Show features young performers - inspiring for your kids. Free in the mall.",tips:"Combine with mall shopping. The Sunday Keiki Hula at 1pm is especially cute. Free and no reservation needed.",region:"Honolulu",wiki:null,tags:["recurring","hula","free","daily","mall","keiki show"]},

// ===== ONGOING EXHIBITIONS =====
{id:380,name:"Bishop Museum: Aloha Bricks '26 - LEGO Exhibition",category:"events",address:"1525 Bernice St, Honolulu",driveTime:"25 min",distance:"12 mi",eventDate:"2026-03-14",eventEndDate:"2026-12-31",description:"LEGO exhibition of Hawaiian landmarks, native species, and legendary tales. Features a free play zone where kids can build. Opens March 14 - perfect timing for your trip!",cost:"Adults $26.95, Kids 4-17 $19.95, Under 4 FREE",hours:"Wed-Mon 9am-5pm",kidInfo:"Kids LOVE this. LEGO builds of Hawaiian landmarks. Free play zone to build their own. Under 4 FREE.",tips:"The LEGO exhibition plus the Science Adventure Center makes Bishop Museum a full-day activity. Under 4 free.",region:"Honolulu",wiki:null,url:"https://www.bishopmuseum.org/",tags:["LEGO","ongoing","kids love it","interactive","free play"]},
{id:381,name:"West Side Story at Diamond Head Theatre",category:"events",address:"520 Makapuu Ave",driveTime:"5 min",distance:"2 mi",eventDate:"2026-03-20",eventEndDate:"2026-04-05",description:"Classic Bernstein/Sondheim musical at the community theater just 5 minutes from your rental! More appropriate for parents/date night (some violent themes).",cost:"From $43",hours:"Various showtimes",kidInfo:"More for parents/date night. Violent themes not ideal for young kids.",tips:"Only 5 minutes from home! Great date night option if you can arrange a sitter. Community theater with professional quality.",region:"East Oahu",wiki:null,url:"https://www.diamondheadtheatre.com/",tags:["theater","close to home","date night","musical"]},

// ===== ACTIVITIES FOR AGES 6-12 =====
{id:400,name:"CLIMB Works Keana Farms Zipline",category:"adventures",address:"1 Enos Rd, Kahuku",driveTime:"55 min",distance:"36 mi",description:"8 dual ziplines (longest nearly half a mile), 2 rappels, 3 sky bridges, ATV ride up through working farm. Kids love tandem racing lines side-by-side with a parent. Incredible North Shore coastline views.",cost:"~$179/person",hours:"Multiple tours daily, 3 hours",kidInfo:"Ages 7+ (5-14 must have adult). Min 42\" tall, 85-270 lbs solo (tandem under 85 lbs). Tandem with parent is a blast.",tips:"Book well in advance. Closed-toe shoes required. Morning tours are less hot.",region:"North Shore",wiki:null,tags:["zipline","tandem","north shore","adrenaline","ages 7+"]},
{id:401,name:"HiClimb Indoor Rock Climbing",category:"adventures",address:"825 Ilaniwai St, Kakaako",driveTime:"15 min",distance:"10 mi",description:"14,000 sq ft gym with 35-foot climbing tower and bouldering walls up to 16 feet. Keiki Lessons available (1.5 hrs, all gear provided). Routes for all skill levels. Great rainy-day activity.",cost:"First visit $25 (includes gear); visitor rate $38 with gear",hours:"8am-11pm weekdays",kidInfo:"Ages 5+. First-timers get free gear rental and orientation. Keiki lessons available. Great for all skill levels.",tips:"First visit includes free gear rental and orientation. Open late. Perfect rainy day activity.",region:"Kakaako",wiki:null,tags:["rock climbing","indoor","rainy day","kakaako","ages 5+"]},
{id:402,name:"The Escape Game Honolulu",category:"adventures",address:"Ala Moana Center, 2nd level near Target",driveTime:"15 min",distance:"9 mi",description:"7 themed escape rooms with Hollywood-quality immersive sets. 'Gold Rush' and 'Playground' are most kid-friendly. Kids 8-12 who like puzzles go wild for these.",cost:"~$47/person",hours:"Open daily, 60 min per game",kidInfo:"Recommended 13+ but younger allowed with adult. Gold Rush and Playground rooms are most kid-friendly.",tips:"Book online in advance. Playground room holds up to 12 players. Great for puzzle-loving kids.",region:"Honolulu",wiki:null,tags:["escape room","puzzles","indoor","rainy day","ala moana"]},
{id:403,name:"Scaventour Outdoor Escape Game",category:"adventures",address:"Marriott Waikiki Beach Resort",driveTime:"15 min",distance:"9 mi",description:"Outdoor scavenger hunt meets escape room. Walk 1.5 miles around Waikiki solving puzzles and cracking 15 locks with a Game Master Guide. Active and engaging for kids who can't sit still.",cost:"Adults $23, Kids $14",hours:"Multiple times daily, ~1.5 hours",kidInfo:"Ages 6+. Kanaloa's Curse designed specifically for ages 6-12. Active outdoor format perfect for energetic kids.",tips:"Great alternative to indoor escape rooms for younger/active kids. 1.5 mile walk keeps everyone moving.",region:"Waikiki",wiki:null,tags:["scavenger hunt","outdoor","waikiki","ages 6+","active"]},
{id:404,name:"iTrampoline Hawaii + Laser Tag",category:"adventures",address:"94-157 Leoleo St, Waipahu",driveTime:"30 min",distance:"18 mi",description:"14,000+ sq ft of connected trampolines, foam pit, dodgeball, slam-dunk hoops, and laser tag arena. Kids 8-12 go absolutely berserk here.",cost:"$18.50 (1 hr) to $32 (4 hrs); Holiday Bounce Pass (trampoline + laser tag) $29.95",hours:"Mon-Thu 10:30am-2pm, extended Fri-Sun",kidInfo:"All ages with different zones by size. Grip socks required. Combine trampoline + laser tag for best value.",tips:"Grip socks required ($3). Mon-Thu hours limited. Combine with K1 Speed nearby for a full day.",region:"West Oahu",wiki:null,tags:["trampoline","laser tag","indoor","high energy","waipahu"]},
{id:405,name:"K1 Speed Indoor Go-Karts",category:"adventures",address:"91-1085 Lexington St, Kapolei",driveTime:"40 min",distance:"25 mi",description:"Electric go-karts on a real indoor track with timed laps and printout race stats. Air-conditioned. Mon-Thu $39 special for 3 races.",cost:"~$50/kid (membership + 2 races)",hours:"Open daily, 1-2 hours",kidInfo:"Height-based: 48\" for junior karts (~age 7-8+). Timed laps with printout stats kids love.",tips:"Height requirement is strict - measure kids before driving out. Mon-Thu $39 special for 3 races. Air-conditioned.",region:"West Oahu",wiki:null,tags:["go-karts","indoor","racing","air conditioned","kapolei"]},
{id:406,name:"Whale Watching Tour",category:"adventures",address:"Departs Kewalo Basin or Waikiki",driveTime:"15 min",distance:"9 mi",description:"Humpback whales breach, tail-slap, and spout just offshore Jan-March. Boats get remarkably close. 40-ton whales launching out of the water is jaw-dropping. Most operators guarantee a sighting or free return trip.",cost:"$47-$80/person (kids discounts available)",hours:"Multiple departures daily, 2 hours",kidInfo:"All ages welcome. Morning tours have calmer seas. Bring Dramamine for motion-sensitive kids.",tips:"Star of Honolulu runs Jan 3 - Mar 21, 2026. Morning tours = calmer seas. March is peak season!",region:"Honolulu",wiki:"Humpback_whale",tags:["whale watching","seasonal","march","ocean","once-in-a-lifetime"]},
{id:407,name:"Stars Above Hawaii Stargazing",category:"adventures",address:"Ko Olina Resort area",driveTime:"45 min",distance:"28 mi",description:"NASA Ambassador astronomer uses computerized telescopes (600x power) to show Saturn's rings, moon craters, galaxies. Weaves in Polynesian star navigation stories. Space-obsessed kids will be mesmerized.",cost:"Adults $39, Children $20",hours:"Start times 8-8:45pm, 1 hour",kidInfo:"Great for ages 6+. Saturn's rings through a telescope is unforgettable. Polynesian navigation stories are captivating.",tips:"Minimal light pollution for Oahu. Combine with sunset dinner at Ko Olina. Start times 8-8:45pm.",region:"West Oahu",wiki:null,tags:["stargazing","astronomy","saturn","polynesian navigation","evening"]},
{id:408,name:"Makapuu Tide Pools",category:"nature",address:"Makapuu Point, past Sea Life Park",driveTime:"15 min",distance:"7 mi",description:"Natural lava rock pools filled with crystal-clear water, tropical fish, and sea urchins. Feels like discovering a secret natural aquarium. The hike down adds to the adventure.",cost:"Free",hours:"Open daily, best at low tide",kidInfo:"Ages 6+ with parent supervision. Bring reef shoes. Like discovering a secret aquarium. No lifeguards.",tips:"Only visit on calm days with low surf. Best at low tide. Bring reef shoes. No lifeguards - supervise closely.",region:"East Oahu",wiki:null,tags:["tide pools","free","close to home","natural aquarium","low tide"]},
{id:409,name:"Turtle Canyon Snorkeling Tour",category:"adventures",address:"Departs Waikiki / Kewalo Basin",driveTime:"15 min",distance:"9 mi",description:"Catamaran to a reef where Hawaiian green sea turtles gather in large numbers. Snorkel in open ocean with flotation devices alongside turtles, tropical fish, and eagle rays. Way more turtles than Hanauma Bay.",cost:"$60-$90/person",hours:"Multiple departures, 2 hours",kidInfo:"Ages 3-5+ depending on operator. Flotation devices provided. Morning tours have best visibility.",tips:"Great step-up after Hanauma Bay experience. Morning tours have best visibility. Way more turtles than Hanauma Bay.",region:"Waikiki",wiki:null,tags:["snorkeling","turtles","catamaran","ocean"]},
{id:410,name:"Stand-Up Paddleboarding",category:"adventures",address:"Waikiki Beach or Kailua Beach",driveTime:"15 min",distance:"9 mi",description:"Perfect blend of surfing and kayaking. In calm Waikiki/Kailua waters kids stand up quickly. Some schools teach kids to catch small waves on the SUP. Spot turtles from the elevated vantage point.",cost:"Rentals ~$48/half-day; private lessons $140-$199",hours:"Daily, 1-2 hours",kidInfo:"Ages 5+. Private lessons recommended for under 14. Kailua is calmer and less crowded than Waikiki.",tips:"Kailua is calmer and less crowded. Morning = glassiest water. Spot turtles from the elevated vantage point.",region:"Various",wiki:null,tags:["SUP","paddleboarding","water sports","kailua","waikiki"]},
{id:411,name:"Boogie Boarding",category:"adventures",address:"Multiple beaches",driveTime:"Varies",description:"Rent a board ($10-20/day) or buy at ABC Store ($15-30). Best beginner beaches: Waikiki, Ala Moana, Kailua. WARNING: Sandy Beach is NOT for kids (notorious injuries). Makapuu is expert only.",cost:"Board rental $10-20/day; buy $15-30",hours:"Anytime",kidInfo:"Ages 6+ at Waikiki (beginner). Ages 8+ confident swimmers at Kailua. NEVER Sandy Beach for kids.",tips:"Fins make a huge difference. Rash guards prevent board rash. Waikiki is the safest for beginners.",region:"Various",wiki:null,tags:["boogie boarding","water sports","beginner friendly","affordable"]},
{id:412,name:"Nocturnal Adventures Glow SUP Tour",category:"adventures",address:"Haleiwa and Waikiki",driveTime:"15-50 min",description:"LED paddleboards illuminate the water beneath you starting just before sunset. High chance of seeing sea turtles swimming around your board. Friday Waikiki tour includes front-row fireworks view from your paddleboard.",cost:"Check nocturnaladventureshawaii.com",hours:"Sunset start, 90 min",kidInfo:"Ages 4+ (4-6 ride with guide; older kids paddle independently). Sea turtles in LED-lit water is magical.",tips:"Friday Waikiki tour includes front-row fireworks view! Book Waikiki location for shorter drive.",region:"Various",wiki:null,url:"https://nocturnaladventureshawaii.com",tags:["glow SUP","sunset","turtles","LED","fireworks friday"]},
{id:413,name:"Family Fishing Charter",category:"adventures",address:"Departs Kewalo Basin, Waikiki, or Haleiwa",driveTime:"15 min",distance:"9 mi",description:"Bottom/reef fishing has frequent bites so kids stay engaged. Catch goatfish, jacks, snappers, triggers. Some charters combine fishing with snorkeling. Keeping and eating your catch is the ultimate reward.",cost:"Half-day private ~$500 + $75/additional; shared trips $100-$150/person",hours:"Morning departures, 4-5 hours",kidInfo:"All ages. Half-day morning trips best for kids. Bottom/reef fishing beats deep-sea trolling for attention spans.",tips:"Bottom/reef fishing is better than deep-sea trolling for kids - more frequent bites. Bring Dramamine.",region:"Various",wiki:null,tags:["fishing","charter","ocean","catch your dinner"]},
{id:414,name:"Keiki Kingdom Indoor Playground",category:"family",address:"1460 S Beretania St, Honolulu",driveTime:"15 min",distance:"8 mi",description:"Indoor playground with various play structures. Good alternative to Kids City Adventure. 10 months to 13 years.",cost:"$22/child for 2 hrs; $32 for 3 hrs; Adults $5",hours:"Open daily",kidInfo:"Ages 10 months - 13 years. Various play structures for different ages. Good rainy day option.",tips:"Good alternative to Kids City if that's too crowded. Adults $5 admission.",region:"Honolulu",wiki:null,tags:["indoor playground","rainy day","toddler friendly"]},
{id:415,name:"OdysseyVR Hawaii",category:"family",address:"International Marketplace, 2330 Kalakaua Ave, Waikiki",driveTime:"15 min",distance:"9 mi",description:"Oahu's dedicated VR arcade with diverse selection of games. Multiple VR stations and experiences. Great for tech-savvy kids.",cost:"Contact (808) 798-1207",hours:"Mon-Thu 10am-10pm; Fri-Sat 10am-11pm; Sun 10am-10pm",kidInfo:"All ages. Multiple VR stations. Great for kids who love technology and gaming.",tips:"In the International Marketplace - combine with shopping and dining in Waikiki.",region:"Waikiki",wiki:null,tags:["VR","arcade","gaming","indoor","waikiki"]},
{id:416,name:"XploreRide XR Bus Tour",category:"family",address:"Departs from Waikiki",driveTime:"15 min",distance:"9 mi",description:"World's first XR sightseeing bus. Transparent screens overlay digital visuals onto real streets - sea turtles swim across windows, ancient volcanoes erupt, Hawaiian legends come alive. Air-conditioned zero-emission electric bus.",cost:"Check xploreride.com",hours:"Multiple departures, 45 min",kidInfo:"Ages 7+. Augmented reality makes a bus tour actually exciting for kids. Air-conditioned.",tips:"Reserve 3-5 days in advance for groups of 4+. Unlike anything else on the island.",region:"Waikiki",wiki:null,url:"https://xploreride.com",tags:["XR","augmented reality","bus tour","unique","air conditioned"]},
{id:417,name:"Banzai Skatepark",category:"adventures",address:"59460 Kamehameha Hwy, Haleiwa",driveTime:"55 min",distance:"35 mi",description:"Three sections with ramps, rails, pool coping, street elements. Located across from legendary Banzai Pipeline. Welcoming local community. Skateboards and skates ONLY - no bikes/scooters.",cost:"Free",hours:"Open daily",kidInfo:"All ages. Bring your own board or rent in Haleiwa. Helmet and pads recommended.",tips:"Across from Banzai Pipeline! Combine with North Shore beach day. Welcoming local skate community.",region:"North Shore",wiki:null,tags:["skatepark","free","north shore","skateboarding"]},
{id:418,name:"Koko Head BMX Track",category:"adventures",address:"Koko Head District Park, Hawaii Kai",driveTime:"8 min",distance:"3 mi",description:"Dirt trail system with twists, turns, and jumps. Occasional organized events. Very close to home for a quick afternoon of riding.",cost:"Free",hours:"Open daily",kidInfo:"Older kids with BMX experience. Check in at park office for waiver forms.",tips:"Super close to home. Great for a quick afternoon activity. Bring your own bike.",region:"Hawaii Kai",wiki:null,tags:["BMX","free","close to home","dirt track"]},
{id:419,name:"Hawaii Nature Center Camp",category:"family",address:"2131 Makiki Heights Dr, Honolulu",driveTime:"20 min",distance:"10 mi",description:"Week-long science-based environmental exploration during spring break. Hikes, fishing, bug hunts, nature games, crafts. Tech-free, hands-on. Field trip beach days included.",cost:"Varies, scholarships available",hours:"8am-2:30pm (aftercare until 5:30pm, $40/day)",kidInfo:"Ages 6-11. March 16-27, 2026 spring break sessions. Tech-free, hands-on learning.",tips:"Register at hawaiinaturecenter.org. Great way for kids to make local friends during spring break.",region:"Honolulu",wiki:null,url:"https://hawaiinaturecenter.org",tags:["nature camp","spring break","ages 6-11","science","hands-on"]},

// ===== ADDITIONAL FROM FILES 06 & 07 =====
{id:420,name:"Waikiki Brewing Company",category:"breweries",address:"1945 Kalakaua Ave, Waikiki",driveTime:"20 min",distance:"9 mi",description:"Brewpub with full food menu right in Waikiki. Good burgers, fish tacos, and house-brewed beers. Relaxed atmosphere. Also has a Kakaako location.",cost:"$$",hours:"Open daily",kidInfo:"Full food menu makes it easy with kids. Relaxed atmosphere.",tips:"Right in Waikiki - good lunch stop while exploring. Also has a Kakaako location.",region:"Waikiki",wiki:null,tags:["brewery","food menu","waikiki","relaxed"]},
{id:421,name:"7-Eleven Musubi Run",category:"local",address:"Various locations (closest in Niu Valley)",driveTime:"5 min",distance:"2 mi",description:"Hawaii 7-Elevens are a local institution. Fresh spam musubi ($2-3), manapua (bao), noodle bowls - all made fresh daily. Locals grab breakfast and snacks here regularly. A uniquely Hawaiian experience.",cost:"$2-5",hours:"24 hours",kidInfo:"Kids love spam musubi. Quick, cheap, and authentically local. Walking-distance option in Niu Valley.",tips:"This sounds weird but Hawaii 7-Elevens are genuinely good. Spam musubi is the go-to. A true local experience.",region:"Aina Haina",wiki:null,tags:["local","spam musubi","cheap eats","24 hours","authentic"]},
{id:422,name:"Crack Seed Store",category:"local",address:"Various locations (try Aina Haina or Kaimuki)",driveTime:"5 min",distance:"2 mi",description:"Distinctly Hawaiian snack shops selling preserved/dried fruits, li hing mui candy, dried cuttlefish. Kids either love it or hate it. A truly local cultural experience.",cost:"$3-8/bag",hours:"Varies by shop",kidInfo:"Fun taste-test adventure for kids. Li hing mui gummy bears are a good starter. Unique to Hawaii.",tips:"Start with li hing mui gummy bears as an intro. Dried mango and arare are safer bets for picky eaters.",region:"Various",wiki:null,tags:["local","crack seed","li hing mui","snacks","cultural"]},
{id:423,name:"Island Brew Coffeehouse",category:"dining",address:"377 Keahole St, Hawaii Kai",driveTime:"5 min",distance:"2 mi",description:"Where local parents grab morning coffee. Outdoor seating, chill vibe. Good acai bowls too. Not a tourist destination - your neighborhood coffee spot.",cost:"$4-8",hours:"Open daily",kidInfo:"Casual outdoor seating. Good acai bowls and smoothies for kids.",tips:"Your local morning coffee spot. Outdoor seating is pleasant. Locals, not tourists.",region:"Hawaii Kai",wiki:null,tags:["coffee","local","close to home","acai bowls","morning"]},
{id:424,name:"Ethel's Grill",category:"dining",address:"232 Kalihi St",driveTime:"25 min",distance:"13 mi",description:"Tiny 10-seat Japanese-Hawaiian diner. Incredible garlic ahi, oxtail soup. Cash only. Lunch hours - arrive early or wait. A true hidden gem.",cost:"$",hours:"Lunch hours only",kidInfo:"Tiny space (10 seats) may be tough with young kids. But the food is incredible.",tips:"CASH ONLY. Arrive early or expect a wait. Garlic ahi is legendary. Only 10 seats.",region:"Kalihi",wiki:null,tags:["japanese-hawaiian","hidden gem","cash only","tiny","garlic ahi"]},
{id:425,name:"USS Bowfin Submarine Museum",category:"cultural",address:"Pearl Harbor",driveTime:"30 min",distance:"16 mi",description:"Walk through a real WWII submarine! Tight quarters but fascinating for kids who like machines and history. Adjacent to Pearl Harbor Memorial.",cost:"Adults $15, Kids 4+ $8",hours:"Open daily",kidInfo:"Kids must be 4+ years old. Tight quarters are exciting for kids. Very hands-on experience.",tips:"Combine with Pearl Harbor visit. The tight submarine quarters make it an adventure for kids.",region:"Pearl Harbor",wiki:"USS_Bowfin",tags:["submarine","wwii","hands-on","pearl harbor"]},
{id:426,name:"Hawaii State Art Museum (HiSAM)",category:"cultural",address:"250 S Hotel St, Downtown",driveTime:"25 min",distance:"11 mi",description:"FREE contemporary Hawaiian art in a beautiful historic building. Small but interesting rotating exhibits. One of Honolulu's best free cultural experiences.",cost:"Free",hours:"Tue-Sat 10am-4pm",kidInfo:"Free and small enough for short attention spans. Beautiful historic building.",tips:"Completely free. Small and manageable. Combine with Chinatown exploration or Iolani Palace.",region:"Downtown",wiki:null,tags:["free","art museum","contemporary","historic building"]},
{id:427,name:"Palolo Valley Public Pool",category:"family",address:"2007 Palolo Ave",driveTime:"15 min",distance:"7 mi",description:"Public swimming pool, just $1 admission. Locals bring their kids for afternoon swims. Way cheaper and less chaotic than beach days when you just need the kids to burn energy.",cost:"$1 admission",hours:"Afternoon hours",kidInfo:"$1 per person! Great for burning energy without a full beach trip. Local families use this daily.",tips:"Only $1! Way cheaper than any other water activity. Good for days when you just need the kids to swim.",region:"Honolulu",wiki:null,tags:["swimming pool","$1","cheap","local","energy burner"]},

// ===== RESTAURANTS (from files 02 & 17) =====
{id:428,name:"Repetti's Pizza and Provisions",category:"dining",address:"377 Keahole St, Ste C5, Honolulu, HI 96825",driveTime:"8 min",distance:"3 mi",description:"Real Italian food made from scratch by someone with 47 years of pizzeria experience. Fresh dough, house-made sauces, generous portions. The rigatoni bolognese is rich and satisfying. Italian sub and meatball sub are some of the best on this side of the island.",cost:"$$",hours:"Daily 11am-9pm",kidInfo:"Very kid-friendly. Casual counter-service, pizza always a hit with kids, generous portions easy to share.",tips:"No reservations, walk-in only. Counter-service ordering. Portions are large - consider sharing.",region:"Hawaii Kai",wiki:null,tags:["pizza","italian","counter-service","close to home","family"]},
{id:429,name:"Mama Pho",category:"dining",address:"820 W Hind Dr, Unit 111, Honolulu, HI 96821",driveTime:"2 min",distance:"0.5 mi",description:"Your neighborhood pho spot in Aina Haina Shopping Center. Family-owned since 2011 using family recipes. Deeply flavorful broth, generous bowls with plenty of meat, fresh herbs, and complimentary vegetable side plate.",cost:"$-$$",hours:"Mon-Thu 11am-9pm, Fri-Sat 11am-10pm, Sun 11am-8pm",kidInfo:"Good for kids - noodle soup is universally appealing. Casual, no-fuss environment.",tips:"Walking distance! Small parking lot can fill at lunch. Grab poke from Foodland in the same shopping center.",region:"Aina Haina",wiki:null,tags:["vietnamese","pho","walking distance","neighborhood","affordable"]},
{id:430,name:"Roy's Hawaii Kai",category:"dining",address:"6600 Kalanianaole Hwy, Honolulu, HI 96825",driveTime:"7 min",distance:"3 mi",description:"Chef Roy Yamaguchi's original flagship restaurant, open 35+ years. Where Hawaiian fusion cuisine was invented. Locally sourced ingredients with Japanese and European techniques. The macadamia-crusted mahi mahi is iconic.",cost:"$$$",hours:"Mon-Thu 4:30-9pm, Fri-Sat 4:30-9:30pm, Sun 4:30-9pm",kidInfo:"Kids menu available. Private dining room works for families. Staff accommodating.",tips:"Reservations strongly recommended via OpenTable. Happy Hour Mon-Thu 4:30-5:30pm. Order the chocolate souffle when you sit down - takes 30 min to prepare.",region:"Hawaii Kai",wiki:null,tags:["hawaiian fusion","fine dining","close to home","iconic","special occasion"]},
{id:431,name:"Tropics Restaurant & Craft House",category:"dining",address:"377 Keahole St, Ste C2, East Honolulu, HI 96825",driveTime:"8 min",distance:"3 mi",description:"Right on Hawaii Kai Marina with gorgeous water views. Elevated bar food with Hawaiian flair - burgers, fresh fish, pupu platters. 20+ flatscreen TVs, pool tables, dart boards. Live music adds to the vibe.",cost:"$$",hours:"Mon-Wed 11am-10pm, Thu-Sat 11am-11pm, Sun 7:30am-10pm",kidInfo:"Excellent for families. Casual atmosphere, familiar food, outdoor seating where kids can move around. Sunday brunch at 7:30am.",tips:"Walk-ins usually fine except Fri/Sat evenings. Sit on the patio for marina views. Good for watching mainland sports.",region:"Hawaii Kai",wiki:null,tags:["sports bar","marina views","family","close to home","live music"]},
{id:432,name:"Kapa Hale",category:"dining",address:"4614 Kilauea Ave, Ste 102, Honolulu, HI 96816",driveTime:"12 min",distance:"4 mi",description:"James Beard semifinalist Chef Keaka Lee's showcase. Takes local Hawaiian ingredients and elevates them with Pacific and Asian influences. Menu changes seasonally. Won People's Choice Best Restaurant at Ilima Awards.",cost:"$$$",hours:"Mon-Tue 5-8:30pm, Wed-Fri 10:30am-2pm & 5-9pm, Sat-Sun 9am-2pm & 5-9pm",kidInfo:"Moderate - more upscale dining. Staff warm and welcoming. Lunch/brunch more relaxed for families than dinner.",tips:"Reservations recommended via OpenTable. Weekend brunch (Sat-Sun 9am) more family-friendly than dinner. Trust the chef's recommendations.",region:"Kahala",wiki:null,tags:["james beard","modern hawaiian","seasonal","best restaurant","elevated"]},
{id:433,name:"Kaimuki Shokudo",category:"dining",address:"1127 11th Ave, Honolulu, HI 96816",driveTime:"15 min",distance:"6 mi",description:"Authentic izakaya in Kaimuki. Lunch: rice bowls and soba. Dinner: full izakaya with small plates for sharing. Cold Duck Soba is one of the best noodle dishes on the island. Fried chicken sells out. Honey Toast with haupia ice cream is unforgettable.",cost:"$$",hours:"Lunch 11:30am-3:30pm; Dinner Sun-Thu 4pm-midnight, Fri-Sat 4pm-1am",kidInfo:"Good for lunch (rice bowls, soba). Dinner izakaya more lively but welcoming to families early evening.",tips:"Order the fried chicken immediately - it sells out. Happy Hour Mon-Fri 3-5pm. Late night hours until midnight/1am.",region:"Kaimuki",wiki:null,tags:["izakaya","japanese","late night","fried chicken","kaimuki"]},
{id:434,name:"Harbor Village Cuisine",category:"dining",address:"7192 Kalanianaole Hwy, Koko Marina",driveTime:"8 min",distance:"3 mi",description:"Dim sum and Chinese cuisine in Koko Marina. Weekend dim sum brunch is the highlight with rolling carts of dumplings, buns, and small dishes.",cost:"$$",hours:"Open daily",kidInfo:"Kids love dim sum - small dishes, lots of variety. Point-and-pick from rolling carts is fun.",gfInfo:"Limited GF options - dim sum is mostly wheat-based. Ask about steamed rice dishes and rice noodle rolls. Call ahead: (808) 395-2311.",tips:"Go for weekend dim sum brunch. Close to home in Koko Marina. Call ahead for dietary needs.",region:"Hawaii Kai",wiki:null,tags:["dim sum","chinese","close to home","koko marina"]},
{id:435,name:"La Tour Cafe",category:"dining",address:"820 W Hind Dr #1291, Aina Haina",driveTime:"2 min",distance:"0.5 mi",description:"French/American cafe in your neighborhood shopping center. Salads, sandwiches, and entrees with a French touch. Walking distance from home.",cost:"$$",hours:"Open daily",kidInfo:"Casual cafe setting. Good variety for picky eaters.",gfInfo:"Salads and some entrees can be modified GF. Ask staff about specific items.",tips:"Walking distance from home. Good for a quick neighborhood meal.",region:"Aina Haina",wiki:null,tags:["french","cafe","walking distance","neighborhood"]},
{id:436,name:"Pieology Aina Haina",category:"dining",address:"820 W Hind Dr, Aina Haina Shopping Center",driveTime:"2 min",distance:"0.5 mi",description:"Build-your-own pizza with gluten-free cauliflower crust option. Walking distance from the rental. Quick, easy, customizable - perfect for picky eaters.",cost:"$",hours:"Open daily",kidInfo:"Kids love building their own pizza. Walking distance. Quick and easy.",gfInfo:"Gluten-free cauliflower crust available as a build-your-own option.",tips:"Walking distance! GF crust available. Good for a quick neighborhood dinner.",region:"Aina Haina",wiki:null,tags:["pizza","build your own","walking distance","gluten-free option"]},
{id:437,name:"Hoku's at The Kahala",category:"dining",address:"5000 Kahala Ave, Kahala Hotel",driveTime:"10 min",distance:"4 mi",description:"Fine dining at the Kahala Hotel with Pacific Rim cuisine. Chef will prepare custom gluten-free meals. Upscale option for a special night out.",cost:"$$$",hours:"Dinner service",kidInfo:"Upscale but accommodating. Good for a special family dinner.",gfInfo:"Chef will prepare custom GF meals. Advance notice appreciated.",tips:"Reserve well in advance. Beautiful hotel setting. Dress code applies.",region:"Kahala",wiki:null,tags:["fine dining","kahala hotel","special occasion","gluten-free"]},
{id:438,name:"Arancino at The Kahala",category:"dining",address:"5000 Kahala Ave, Kahala Hotel",driveTime:"10 min",distance:"4 mi",description:"Award-winning Italian at the Kahala Hotel. Beautiful al fresco setting, outstanding pasta. GF pasta available. Best for a special occasion.",cost:"$$$",hours:"Open daily",kidInfo:"Beautiful setting. Pasta is always kid-friendly. Staff accommodating with modifications.",gfInfo:"GF pasta available. Staff accommodating with modifications.",tips:"Reservations required. Beautiful al fresco dining. Award-winning Italian.",region:"Kahala",wiki:null,tags:["italian","kahala hotel","special occasion","al fresco","gluten-free pasta"]},
{id:439,name:"Town Kaimuki",category:"dining",address:"3435 Waialae Ave, Kaimuki",driveTime:"15 min",distance:"6 mi",description:"Farm-to-table restaurant in the heart of Kaimuki's restaurant row. Locally sourced, seasonal menu. Many dishes naturally gluten-free or easily modified.",cost:"$$",hours:"Lunch & dinner",kidInfo:"Seasonal menu with approachable options. Casual Kaimuki vibe.",gfInfo:"Many dishes naturally GF or easily modified. Locally sourced seasonal ingredients.",tips:"In the heart of Kaimuki's restaurant scene. Combine with Third Fridays or a walk along Waialae Ave.",region:"Kaimuki",wiki:null,tags:["farm to table","kaimuki","seasonal","gluten-free friendly"]},
{id:440,name:"Zippy's",category:"dining",address:"Multiple locations (closest: 5450 Kalanianaole Hwy, Niu Valley)",driveTime:"5 min",distance:"2 mi",description:"Hawaii's iconic local chain restaurant. Open 24 hours at most locations. Plate lunches, chili, saimin, Napoleon's Bakery counter. A true Hawaii institution - you have to try it at least once.",cost:"$",hours:"Most locations 24 hours",kidInfo:"Very kid-friendly. Familiar comfort food. Quick and easy. Napoleon's Bakery for treats.",gfInfo:"Limited GF - 2 Egg Breakfasts (no toast), plates with rice, salads (no croutons). Cross-contamination risk.",tips:"Try it at least once - it's a Hawaii institution. Chili is iconic. Napoleon's Bakery counter for malasada-style pastries.",region:"Various",wiki:"Zippy%27s",tags:["local chain","24 hours","plate lunch","institution","affordable"]},
{id:441,name:"Livestock Tavern",category:"dining",address:"49 N Hotel St, Chinatown",driveTime:"25 min",distance:"11 mi",description:"New American restaurant in Chinatown with a farm-to-table concept. Chef accommodates dietary needs. Seasonal menu with craft cocktails. Great date night spot.",cost:"$$$",hours:"Dinner service",kidInfo:"More of a date-night spot. Chinatown location good for adult evening out.",gfInfo:"Chef accommodates dietary needs. Farm-to-table with seasonal menu.",tips:"Best as a date night. Combine with Chinatown exploration. Reserve in advance.",region:"Chinatown",wiki:null,tags:["new american","farm to table","date night","chinatown"]},
{id:442,name:"MW Restaurant",category:"dining",address:"1538 Kapiolani Blvd",driveTime:"20 min",distance:"10 mi",description:"Hawaiian Regional cuisine by husband-wife chef team. Chef-driven menu with many GF options. Staff trained on allergens. One of Honolulu's best upscale dining experiences.",cost:"$$$",hours:"Lunch & dinner",kidInfo:"Staff trained on allergens and dietary needs. Upscale but welcoming.",gfInfo:"Chef-driven menu with many GF options. Staff trained on allergens.",tips:"One of Honolulu's best. Reserve in advance. Great for a special dinner out.",region:"Honolulu",wiki:null,tags:["hawaiian regional","chef-driven","special occasion","gluten-free friendly"]},
{id:443,name:"Senia",category:"dining",address:"75 N King St, Chinatown",driveTime:"25 min",distance:"11 mi",description:"Modern Hawaiian/Pacific cuisine with tasting menu that can be fully adapted for gluten-free. One of Honolulu's most acclaimed restaurants. Advance notice appreciated for dietary needs.",cost:"$$$",hours:"Dinner service",kidInfo:"Tasting menu format - better for older kids or date night.",gfInfo:"Tasting menu can be fully adapted for GF. Advance notice appreciated.",tips:"One of Honolulu's finest. Reserve well in advance. Best as a date night. Tasting menu is the way to go.",region:"Chinatown",wiki:null,tags:["tasting menu","acclaimed","chinatown","gluten-free adaptable","date night"]},
{id:444,name:"Hy's Steak House",category:"dining",address:"2440 Kuhio Ave, Waikiki",driveTime:"20 min",distance:"9 mi",description:"Classic fine dining steakhouse in Waikiki. Steaks, seafood, and vegetables all naturally gluten-free. Old-school glamour and impeccable service.",cost:"$$$",hours:"Dinner nightly",kidInfo:"Classic steakhouse - better for older kids or date night. Impeccable service.",gfInfo:"Steaks, seafood, vegetables all naturally GF. Classic fine dining.",tips:"Great special occasion or date night option. Classic Waikiki institution. Reserve in advance.",region:"Waikiki",wiki:null,tags:["steakhouse","fine dining","waikiki","gluten-free","classic"]},
{id:445,name:"Marukame Udon",category:"dining",address:"2310 Kuhio Ave, Waikiki",driveTime:"20 min",distance:"9 mi",description:"Popular Japanese udon shop in Waikiki with fresh-made noodles. Watch noodles being made through glass. Lines are long but move fast. NOTE: Udon is wheat-based - NOT gluten-free.",cost:"$",hours:"Open daily",kidInfo:"Kids love watching noodles being made. Lines move fast. Very affordable.",gfInfo:"NOT GF-friendly - udon is wheat-based. Skip if celiac.",tips:"Lines look intimidating but move very fast. Fresh noodles made right in front of you. Under $10 per person.",region:"Waikiki",wiki:null,tags:["udon","japanese","waikiki","affordable","NOT gluten-free"]},
{id:446,name:"The Surfing Pig",category:"dining",address:"3605 Waialae Ave, Kaimuki",driveTime:"18 min",distance:"7 mi",description:"Gastropub with Hawaiian-style small plates and strong cocktails. Won multiple Diner's Choice awards. Good for a fun evening out on Kaimuki's restaurant row.",cost:"$$",hours:"Dinner service",kidInfo:"Casual gastropub atmosphere. Good small plates for sharing.",tips:"Won multiple Diner's Choice awards. Great for a fun evening in Kaimuki. Combine with Third Fridays.",region:"Kaimuki",wiki:null,tags:["gastropub","small plates","cocktails","kaimuki","awards"]},
{id:447,name:"Off the Wall Craft Beer & Wine",category:"breweries",address:"1012 Kapahulu Ave",driveTime:"18 min",distance:"8 mi",description:"Not a brewery but an excellent craft beer bar with rotating taps and good food. Casual neighborhood vibe in the Kapahulu corridor.",cost:"$$",hours:"Open daily",kidInfo:"Casual neighborhood bar. More of an evening adult spot.",tips:"Great beer selection with rotating taps. Good food menu too. Casual Kapahulu neighborhood vibe.",region:"Kapahulu",wiki:null,tags:["craft beer","bar","kapahulu","rotating taps"]},

// ===== TOP 5 SHAVE ICE =====
{id:448,name:"Matsumoto Shave Ice",category:"local",address:"66-111 Kamehameha Hwy, Haleiwa",driveTime:"50 min",distance:"32 mi",description:"The most famous shave ice in Hawaii since 1951. Iconic rainbow shave ice. Lines can be 30+ minutes on weekends but it's a North Shore institution. Get it with ice cream on the bottom and condensed milk on top.",cost:"$4-7",hours:"9am-6pm daily",kidInfo:"Kids love the rainbow colors. Lines are long but worth it. Ice cream on the bottom is a must.",tips:"THE iconic shave ice spot. Lines are long on weekends - go midweek. Get ice cream on the bottom and li hing mui powder. Combine with North Shore day trip.",region:"North Shore",wiki:"Matsumoto_Shave_Ice",tags:["shave ice","iconic","north shore","since 1951","rainbow"]},
{id:449,name:"Waiola Shave Ice",category:"local",address:"2135 Waiola St, Honolulu",driveTime:"18 min",distance:"8 mi",description:"Many locals say this is the BEST shave ice on the island - finer texture than Matsumoto's. Former President Obama's favorite (he grew up nearby). Less touristy, more local. The shave is incredibly fine and fluffy.",cost:"$4-7",hours:"10am-6:30pm daily",kidInfo:"Kids love the ultra-fine, fluffy ice. Less crowded than Matsumoto's. Good variety of flavors.",tips:"Obama's favorite shave ice spot. Finer texture than Matsumoto's. Try with mochi balls and azuki beans. Less crowded than the tourist spots.",region:"Honolulu",wiki:null,tags:["shave ice","obama favorite","finest texture","local favorite"]},
{id:450,name:"Shimazu Shave Ice",category:"local",address:"3117 Waialae Ave, Kaimuki",driveTime:"15 min",distance:"6 mi",description:"Hidden gem in Kaimuki using only real fruit syrups - no artificial flavors or colors. Hand-shaved ice gives it an incredible texture. Small family operation that locals fiercely protect.",cost:"$5-8",hours:"Check hours (limited)",kidInfo:"Real fruit flavors are great for kids. No artificial anything. Worth seeking out.",tips:"Real fruit syrups only - no artificial anything. In Kaimuki so combine with dinner at a nearby restaurant. Limited hours.",region:"Kaimuki",wiki:null,tags:["shave ice","real fruit","kaimuki","hidden gem","no artificial"]},
{id:451,name:"Island Snow",category:"local",address:"130 Kailua Rd, Kailua",driveTime:"25 min",distance:"12 mi",description:"Another Obama favorite - he stops here on vacation. Premium shave ice in Kailua town. Known for their incredibly fine ice and creative flavor combinations. Perfect post-beach stop after Kailua or Lanikai.",cost:"$5-8",hours:"10am-6pm daily",kidInfo:"Great post-beach treat. Fine fluffy ice kids love. Creative flavors.",tips:"Obama stops here on vacation! Perfect after a Kailua Beach day. Try the house special combinations.",region:"Windward",wiki:null,tags:["shave ice","obama","kailua","post-beach","premium"]},

// ===== FOOD SOURCES (from file 10) =====
{id:452,name:"HanaPa'a Market",category:"foodsources",address:"7192 Kalanianaole Hwy, Koko Marina",driveTime:"8 min",distance:"3 mi",description:"Dedicated poke and plate lunch shop in Koko Marina. Known for their Original Spicy Tuna Sandwich and customizable poke bowls. Quick, reliable, close to home.",cost:"$12-16/bowl",hours:"Open daily",kidInfo:"Quick poke bowl stop. Close to home. Customizable bowls let kids pick what they want.",tips:"Good everyday poke option in Koko Marina. The spicy tuna sandwich is their signature.",region:"Hawaii Kai",wiki:null,tags:["poke","plate lunch","close to home","koko marina"]},
{id:453,name:"Paradise Poke Hawaii",category:"foodsources",address:"333 Keahole St, Hawaii Kai Towne Center",driveTime:"8 min",distance:"3 mi",description:"Fisherman's family operation using locally-sourced fish from local boats. Good everyday poke spot with garlic shrimp and onigiri options too.",cost:"$12-16/bowl",hours:"Open daily",kidInfo:"Onigiri (rice balls) are a great kid option. Close to home.",tips:"Family-run, locally sourced. Good value for quality. Close to home in Hawaii Kai Towne Center.",region:"Hawaii Kai",wiki:null,tags:["poke","local fish","close to home","family-run"]},
{id:454,name:"Ono Seafood Kapahulu (Original)",category:"foodsources",address:"747 Kapahulu Ave",driveTime:"15 min",distance:"7 mi",description:"The original location since 1995. Consistently top-3 poke on the island. Judy Sakuma's iconic sauces. Lines are common but worth the wait. The Hawaiian-style ahi is the gold standard.",cost:"$14-18/bowl",hours:"Tue-Sat 9am-4pm",kidInfo:"Quick poke bowl stop. Lines can be long.",tips:"The original and best. Hawaiian-style ahi is the gold standard. Lines are worth it. Tue-Sat only.",region:"Kapahulu",wiki:null,tags:["poke","original","gold standard","iconic","since 1995"]},
{id:455,name:"Ali'i Fish Market",category:"foodsources",address:"2320 S King St, Moiliili",driveTime:"20 min",distance:"9 mi",description:"Owner Baron Miho buys at the Honolulu Fish Auction every morning. 4.9 Google stars. Featured in Honolulu Magazine. Hidden gem - look past Niu Soft Serve at the entrance.",cost:"Market pricing",hours:"Wed-Sun 9:30am-4pm",kidInfo:"Quick poke bowl stop. Educational to see auction-fresh fish.",tips:"Fish bought at the Honolulu Fish Auction every morning. 4.9 Google stars. Hidden gem.",region:"Honolulu",wiki:null,tags:["fish auction","poke","hidden gem","4.9 stars"]},
{id:456,name:"Richard's Meat Market",category:"foodsources",address:"906 Kaaahi Pl",driveTime:"25 min",distance:"13 mi",description:"Est. 1980. Outstanding quality at prices well below competitors. Boneless prime rib at less than half competitor prices. Delivers to most parts of the island.",cost:"Competitive pricing",hours:"Mon-Fri 7:30am-4:30pm",kidInfo:"Great for BBQ supply runs.",tips:"Best value for quality meat on the island. Prime rib prices are unbeatable. Delivers too. Mon-Fri only.",region:"Honolulu",wiki:null,tags:["butcher","prime rib","value","delivery","since 1980"]},
{id:457,name:"Higa Meat & Pork Market",category:"foodsources",address:"2613 Waiwai Lp",driveTime:"25 min",distance:"12 mi",description:"Family-owned for 74+ years. Originally wholesale, now retail too. Consistent quality, great bulk prices. Call or email for next-day pickup/delivery.",cost:"Bulk pricing",hours:"Open daily",kidInfo:"Good for stocking up on BBQ meats.",tips:"74+ years family-owned. Good bulk prices. Call ahead for next-day orders.",region:"Honolulu",wiki:null,tags:["butcher","wholesale","family-owned","74 years","bulk"]},
{id:458,name:"Honolulu Fish Company",category:"foodsources",address:"824 Gulick Ave",driveTime:"25 min",distance:"12 mi",description:"Founded by a marine biologist. Supplies 3,000+ restaurant customers including top chefs. All fish hook-caught (no nets). Also carries A5 wagyu. Mon-Fri 4:30am-1pm.",cost:"Market pricing",hours:"Mon-Fri 4:30am-1pm",kidInfo:"Very early hours. More of an adult food-nerd destination.",tips:"Founded by a marine biologist. All hook-caught fish. Also has A5 wagyu. Go early - opens 4:30am.",region:"Honolulu",wiki:null,tags:["hook-caught","marine biologist","restaurant supplier","A5 wagyu"]},

// ===== BEACHES & NATURE (missing from files 03, 04, 06) =====
{id:459,name:"Kawaikui Beach Park",category:"beaches",address:"Kalanianaole Hwy, Aina Haina",driveTime:"2 min",distance:"0.5 mi",description:"Your neighborhood park with large grassy area, shade trees, picnic tables. Views toward Koko Head. Rocky shoreline (not for swimming) but great for exploration and picnics. Walking distance!",cost:"Free",hours:"Open daily",kidInfo:"Walking distance! Large grassy area for play. Not for swimming but good for exploration.",tips:"Your closest park - walking distance. Great for morning walks, picnics, and letting kids run. Views of Koko Head.",region:"Aina Haina",wiki:null,tags:["walking distance","park","picnic","free","neighborhood"]},
{id:460,name:"Waimea Bay",category:"beaches",address:"61-031 Kamehameha Hwy, Haleiwa",driveTime:"50 min",distance:"32 mi",description:"One of the most famous beaches in the world. Giant waves in winter (NOT safe for swimming Nov-Feb). In summer, the bay becomes calm with excellent jumping rock. Beautiful any time of year.",cost:"Free",hours:"Open daily",kidInfo:"Only safe for swimming in summer (May-Sept). Giant winter waves are spectacular to WATCH. The jumping rock is summer-only.",tips:"Check surf report before going. Winter = giant waves (watch only). Summer = calm bay with jumping rock. Beautiful year-round for photos.",region:"North Shore",wiki:"Waimea_Bay",tags:["famous","north shore","giant waves","jumping rock","seasonal"]},
{id:461,name:"Sunset Beach",category:"beaches",address:"Kamehameha Hwy, Haleiwa",driveTime:"55 min",distance:"35 mi",description:"2 miles of golden sand, one of the most famous surf spots in the world. Spectacular sunsets. Winter waves are massive (watch only). Summer can be calm enough for wading.",cost:"Free",hours:"Open daily",kidInfo:"NOT safe for swimming in winter. Great for sand play and watching surfers. Summer calmer.",tips:"Check conditions before going. The sunsets here are legendary. Winter = watch the pros surf huge waves.",region:"North Shore",wiki:"Sunset_Beach",tags:["famous","sunset","north shore","surfing","2 miles"]},
{id:462,name:"Electric Beach (Kahe Point)",category:"beaches",address:"Farrington Hwy, Kapolei",driveTime:"45 min",distance:"28 mi",description:"Named for the power plant next door that pumps warm water into the ocean, attracting massive schools of fish, turtles, and dolphins. One of the best free snorkeling spots on Oahu.",cost:"Free",hours:"Open daily",kidInfo:"Strong current - only for confident swimmers ages 8+. Not suitable for young kids in the water but great for watching from shore.",tips:"Current can be strong - experienced swimmers only. The warm water discharge attracts incredible marine life. Dolphins are regularly seen here.",region:"West Oahu",wiki:null,tags:["snorkeling","dolphins","turtles","free","power plant"]},
{id:463,name:"Shangri La Museum of Islamic Art",category:"cultural",address:"4055 Papu Circle, Black Point",driveTime:"10 min",distance:"4 mi",description:"Doris Duke's stunning oceanfront estate with 4,000+ Islamic art objects. Tours depart from Honolulu Museum of Art. KIDS UNDER 7 NOT ALLOWED - perfect for a parents-only excursion!",cost:"$20-45",hours:"Tours depart from Honolulu Museum of Art",kidInfo:"Kids under 7 NOT allowed. Perfect for a parents-only outing while kids are with a sitter.",tips:"Close to home! Book through Honolulu Museum of Art. Great parents-only activity while someone watches the kids.",region:"Kahala",wiki:"Shangri_La_(Honolulu)",tags:["museum","islamic art","oceanfront","parents only","no kids under 7"]},
{id:464,name:"Lyon Arboretum",category:"nature",address:"3860 Manoa Rd",driveTime:"25 min",distance:"11 mi",description:"194-acre rainforest botanical garden in Manoa Valley. Over 5,000 tropical plant species. Gentle trails through lush vegetation. Adjacent to Manoa Falls trailhead.",cost:"$5 suggested donation",hours:"Mon-Fri 8am-4pm, Sat 8am-3pm",kidInfo:"Gentle trails suitable for kids. Lush rainforest setting. Combine with Manoa Falls.",tips:"Combine with Manoa Falls (same road). Less crowded than Hoomaluhia. 194 acres of tropical plants. Bring bug spray.",region:"Honolulu",wiki:"Lyon_Arboretum",tags:["botanical garden","rainforest","manoa","5000 species"]},
{id:465,name:"Kuliouou Ridge Trail",category:"hikes",address:"Kuliouou, off Kalanianaole Hwy",driveTime:"5 min",distance:"2 mi",description:"4.5-mile round-trip hike from very close to home with panoramic views of Koko Head, Koko Crater, Hawaii Kai, and the windward coast. NOT for young kids (steep sections, 1,800ft elevation gain).",cost:"Free",hours:"Sunrise to sunset",kidInfo:"NOT suitable for young kids - steep, 4.5 miles, 1,800ft gain. Good for a parent solo hike while partner watches kids.",tips:"Close to home but challenging. Great for a solo parent morning hike. Bring lots of water. Views are stunning from the ridge.",region:"East Oahu",wiki:null,tags:["ridge hike","close to home","challenging","panoramic views","solo parent"]},
{id:466,name:"Honolulu Museum of Art",category:"cultural",address:"900 S Beretania St",driveTime:"20 min",distance:"10 mi",description:"World-class art collection with Asian, European, American, Pacific art in beautiful galleries with courtyards and koi ponds. Free Family Sundays with art activities for kids. Adults $20, kids 4-17 $8.",cost:"Adults $20, Kids 4-17 $8, under 4 free",hours:"Tue-Sun 10am-6pm",kidInfo:"Free Family Sundays (first Sunday) with kid art activities. Beautiful courtyard with koi fish.",tips:"Free on first Sunday of each month. Beautiful courtyard with koi ponds. Combine with Chinatown lunch.",region:"Honolulu",wiki:"Honolulu_Museum_of_Art",tags:["art museum","world-class","free sundays","koi ponds","cultural"]},

// ===== ADDITIONAL EVENTS (from file 11) =====
{id:467,name:"Kailua Art & Night Market",category:"events",address:"Kailua Town Center, Kailua",driveTime:"25 min",distance:"12 mi",recurring:"Monthly",description:"Monthly art and night market in Kailua town with local artisans, food vendors, and live entertainment. Great evening outing combined with a Kailua beach day.",cost:"Free entry",hours:"Evening",kidInfo:"Family-friendly evening market. Food vendors and art. Combine with a Kailua beach day.",tips:"Check dates - monthly event. Great to combine with Kailua Beach day. Local artisans and good food.",region:"Windward",wiki:null,tags:["night market","art","kailua","monthly","evening"]},
{id:468,name:"Waikiki Farmers Market",category:"events",address:"Hyatt Regency Waikiki, 2424 Kalakaua Ave",driveTime:"20 min",distance:"9 mi",recurring:"Tue & Thu",description:"Twice-weekly farmers market right in Waikiki. Local produce, prepared foods, crafts. Smaller and more accessible than KCC market. Tuesday and Thursday afternoons.",cost:"Free entry",hours:"Tue & Thu 4-8pm",kidInfo:"Smaller market - less overwhelming for kids than KCC. Good food options.",tips:"More accessible than KCC if you're in Waikiki area. Tuesday and Thursday afternoons. Good prepared food options.",region:"Waikiki",wiki:null,tags:["farmers market","waikiki","twice weekly","afternoon"]},
{id:469,name:"Kakaako Farmers Market",category:"events",address:"Ward Village, Kakaako",driveTime:"20 min",distance:"10 mi",recurring:"Saturday",description:"Saturday morning farmers market in the heart of Kakaako. Local produce, artisan food vendors, live music. Great complement or alternative to KCC market.",cost:"Free entry",hours:"Saturday 8am-12pm",kidInfo:"Good food vendors. Combine with Kakaako street art walk. Family-friendly.",tips:"Alternative to KCC market. In the middle of Kakaako's art/brewery district. Combine with mural walk.",region:"Kakaako",wiki:null,tags:["farmers market","saturday","kakaako","artisan food"]}
];
